// Split feature section: intro + placeholder image + expandable feature accordion.
// Props: { content, theme }. Original copy + neutral placeholder media only.
import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence, useReducedMotion } from "framer-motion";

export default function Section({ content, theme }) {
  const c = content || {};
  const title = c.title || "Design conversion-ready websites with complete control";
  const description = c.description ||
    "Deliver fast, engaging websites with a builder designed to optimize performance, enhance user experience, and scale effortlessly.";

  const items = (c.items && c.items.length ? c.items : [
    { title: "Designs with total freedom", text: "Build brand-consistent, engaging pages without writing code. Arrange every element, layer in motion, and manage shared variables from one place." },
    { title: "Marketing built right in", text: "Capture leads, run experiments, and connect your favorite tools so campaigns launch the moment a page goes live." },
    { title: "Dynamic sites that scale", text: "Drive content from structured collections and reuse layouts, so a handful of templates power thousands of pages." },
    { title: "Online stores that win sales", text: "Turn visitors into customers with flexible product layouts, fast checkout, and a storefront that stays on brand." },
  ]);

  // Track container width so responsiveness + media sizing adapt to the real
  // available space (matchMedia/vw are wrong inside preview frames).
  const rootRef = useRef(null);
  const [w, setW] = useState(1200);
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const ro = new ResizeObserver(() => setW(el.clientWidth));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const narrow = w < 820;

  const [open, setOpen] = useState(0);
  const reduce = useReducedMotion();

  const radius = theme.radius || "16px";
  const line = theme.borderColor;
  const soft = theme.surfaceColor;
  const faint = theme.mutedTextColor;

  // Media height scales with the width it will actually occupy, then clamps so it
  // never gets huge (stacked) or too short — always fits, never cut.
  const clamp = (min, val, max) => Math.max(min, Math.min(max, val));
  const colWidth = narrow ? w - 40 : (Math.min(w, 1200) - 56) / 2; // padding / gap aware
  const mediaHeight = Math.round(clamp(200, colWidth * 0.72, 360));

  return (
    <section
      ref={rootRef}
      style={{
        background: theme.backgroundColor,
        color: theme.textColor,
        fontFamily: theme.bodyFont,
        padding: narrow ? "48px 20px" : "88px 64px",
      }}
    >
      <div style={{ maxWidth: 1200, margin: "0 auto" }}>
        <h2 style={{
          fontFamily: theme.headingFont, fontWeight: 800, letterSpacing: "-0.02em",
          lineHeight: 1.05, fontSize: narrow ? 34 : 56, margin: 0, maxWidth: 900, color: theme.textColor,
        }}>{title}</h2>
        <p style={{ marginTop: 20, fontSize: narrow ? 16 : 19, lineHeight: 1.6, color: faint, maxWidth: 620 }}>
          {description}
        </p>

        <div style={{
          marginTop: narrow ? 40 : 64, display: "grid",
          gridTemplateColumns: narrow ? "1fr" : "1fr 1fr", gap: narrow ? 28 : 56, alignItems: "center",
        }}>
          {/* Simple placeholder image — height scales to the space, clamped so it fits */}
          <div style={{
            borderRadius: radius,
            border: "1px solid " + line,
            background: soft,
            width: "100%",
            height: mediaHeight,
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "center",
            gap: 4,
            textAlign: "center",
            padding: 24,
            boxSizing: "border-box",
          }}>
            {/* Icon in a soft badge */}
            <div style={{
              width: 56, height: 56, borderRadius: 16,
              background: theme.backgroundColor,
              border: "1px solid " + line,
              display: "grid", placeItems: "center",
              marginBottom: 10,
              boxShadow: "0 2px 6px rgba(0,0,0,0.04)",
            }}>
              <svg width="28" height="28" viewBox="0 0 24 24" fill="none" style={{ color: faint }} aria-label="Image placeholder">
                <rect x="3" y="4" width="18" height="16" rx="3" stroke="currentColor" strokeWidth="1.6" />
                <circle cx="8.5" cy="9.5" r="1.9" fill="currentColor" />
                <path d="M3.5 16.5 8 12a1.7 1.7 0 0 1 2.4 0l3.3 3.3M13 14.2l2.4-2.4a1.7 1.7 0 0 1 2.4 0l2.7 2.7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
            </div>
            <p style={{ margin: 0, fontSize: 15, fontWeight: 600, color: theme.textColor }}>Add an image</p>
            <p style={{ margin: 0, fontSize: 12.5, color: faint }}>Recommended 1200 × 900</p>
          </div>

          {/* Accordion */}
          <div>
            {items.map((it, i) => {
              const isOpen = open === i;
              return (
                <div key={i} style={{ borderTop: "1px solid " + line, padding: "4px 0" }}>
                  <button
                    type="button" onClick={() => setOpen(isOpen ? -1 : i)} aria-expanded={isOpen}
                    style={{
                      width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between",
                      gap: 16, padding: "20px 0", background: "transparent", border: 0, cursor: "pointer",
                      textAlign: "left", color: theme.textColor,
                      fontFamily: theme.headingFont, fontWeight: 700, fontSize: narrow ? 18 : 22,
                    }}
                  >
                    <span>{it.title}</span>
                    <span style={{ fontSize: 26, lineHeight: 1, color: faint, flexShrink: 0 }}>{isOpen ? "–" : "+"}</span>
                  </button>
                  <AnimatePresence initial={false}>
                    {isOpen && it.text && (
                      <motion.div
                        initial={reduce ? false : { height: 0, opacity: 0 }}
                        animate={{ height: "auto", opacity: 1 }}
                        exit={reduce ? { opacity: 0 } : { height: 0, opacity: 0 }}
                        transition={{ duration: 0.28, ease: [0.22, 1, 0.36, 1] }}
                        style={{ overflow: "hidden" }}
                      >
                        <p style={{ margin: 0, paddingBottom: 22, fontSize: 15.5, lineHeight: 1.65, color: faint, maxWidth: 460 }}>
                          {it.text}
                        </p>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>
              );
            })}
            <div style={{ borderTop: "1px solid " + line }} />
          </div>
        </div>
      </div>
    </section>
  );
}

// Feature showcase: heading + CTA, then a row of media cards with floating chips.
// Props: { content, theme }. Original copy + neutral placeholder media only —
// no brand logos, no external images, no copied text.
import { useState, useRef, useEffect } from "react";
import { motion, useReducedMotion } from "framer-motion";

export default function Section({ content, theme }) {
  const c = content || {};
  const title = c.title || "Manage websites with confidence and control";
  const cta = c.primaryButtonLabel || "Get started";

  const items = (c.items && c.items.length ? c.items : [
    { title: "Hosting", text: "High-performance cloud hosting that stays fast, secure, and effortless to scale.", chip: "24/7 support" },
    { title: "Domains", text: "Search, buy, and connect a custom domain in a few clicks — no config required.", chip: "Instant match" },
    { title: "Deliverability", text: "Make sure your critical emails land in the inbox with reliable, zero-setup delivery.", chip: "99% delivered" },
  ]);

  // Container-query responsiveness (matchMedia breaks inside preview frames).
  const rootRef = useRef(null);
  const [w, setW] = useState(1280);
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const ro = new ResizeObserver(() => setW(el.clientWidth));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const narrow = w < 720;
  const mid = w >= 720 && w < 1040;
  const cols = narrow ? "1fr" : mid ? "1fr 1fr" : "1fr 1fr 1fr";

  const reduce = useReducedMotion();
  const accent = theme.accentColor;
  const line = theme.borderColor;
  const soft = theme.surfaceColor;
  const faint = theme.mutedTextColor;
  const radius = theme.radius || "18px";

  return (
    <section
      ref={rootRef}
      style={{
        background: theme.backgroundColor,
        color: theme.textColor,
        fontFamily: theme.bodyFont,
        padding: narrow ? "48px 20px" : "88px 64px",
      }}
    >
      <div style={{ maxWidth: 1240, margin: "0 auto" }}>
        {/* Header row */}
        <div style={{
          display: "flex", gap: 24, alignItems: narrow ? "flex-start" : "flex-end",
          justifyContent: "space-between", flexDirection: narrow ? "column" : "row",
        }}>
          <h2 style={{
            fontFamily: theme.headingFont, fontWeight: 800, letterSpacing: "-0.02em",
            lineHeight: 1.05, fontSize: narrow ? 34 : 52, margin: 0, maxWidth: 640, color: theme.textColor,
          }}>{title}</h2>
          {cta && (
            <button type="button" style={{
              flexShrink: 0, background: theme.textColor, color: theme.backgroundColor,
              border: 0, borderRadius: 999, padding: "13px 26px", fontWeight: 600, fontSize: 15,
              cursor: "pointer", fontFamily: theme.bodyFont,
            }}>{cta}</button>
          )}
        </div>

        {/* Cards */}
        <div style={{ marginTop: narrow ? 36 : 56, display: "grid", gridTemplateColumns: cols, gap: 24 }}>
          {items.map((it, i) => (
            <motion.div
              key={i}
              initial={reduce ? false : { opacity: 0, y: 16 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true, margin: "-40px" }}
              transition={{ duration: 0.4, delay: i * 0.08, ease: [0.22, 1, 0.36, 1] }}
            >
              {/* Media placeholder with a floating chip */}
              <div style={{
                position: "relative",
                borderRadius: radius,
                overflow: "hidden",
                aspectRatio: "4 / 3",
                border: "1px solid " + line,
                background: "linear-gradient(135deg," + accent + "22 0%," + accent + "55 100%)",
                display: "grid",
                placeItems: "center",
              }}>
                {/* neutral image glyph */}
                <div style={{
                  width: 52, height: 52, borderRadius: 14, background: soft,
                  border: "1px solid " + line, display: "grid", placeItems: "center", opacity: 0.9,
                }}>
                  <svg width="26" height="26" viewBox="0 0 24 24" fill="none" style={{ color: faint }}>
                    <rect x="3" y="4" width="18" height="16" rx="3" stroke="currentColor" strokeWidth="1.6" />
                    <circle cx="8.5" cy="9.5" r="1.9" fill="currentColor" />
                    <path d="M3.5 16.5 8 12a1.7 1.7 0 0 1 2.4 0l3.3 3.3M13 14.2l2.4-2.4a1.7 1.7 0 0 1 2.4 0l2.7 2.7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" />
                  </svg>
                </div>
                {/* floating chip */}
                {it.chip && (
                  <div style={{
                    position: "absolute", left: 16, bottom: 16,
                    display: "inline-flex", alignItems: "center", gap: 8,
                    background: soft, color: theme.textColor,
                    borderRadius: 999, padding: "9px 14px", fontSize: 13, fontWeight: 600,
                    boxShadow: "0 8px 24px rgba(0,0,0,0.12)",
                  }}>
                    <span style={{ display: "grid", placeItems: "center", width: 18, height: 18, borderRadius: 999, background: accent }}>
                      <svg width="11" height="11" viewBox="0 0 24 24" fill="none"><path d="m5 12.5 4 4 10-10" stroke="#fff" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round" /></svg>
                    </span>
                    {it.chip}
                  </div>
                )}
              </div>

              {/* Copy */}
              <h3 style={{
                margin: narrow ? "16px 0 8px" : "22px 0 10px",
                fontFamily: theme.headingFont, fontWeight: 700, fontSize: narrow ? 22 : 26, color: theme.textColor,
              }}>{it.title}</h3>
              <p style={{ margin: 0, fontSize: 16, lineHeight: 1.6, color: faint, maxWidth: 360 }}>{it.text}</p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}

// Feature carousel driven by a PINNED vertical→horizontal scroll (same mechanic
// as the Horizontal Scroll Gallery): the section pins while the feature row
// slides left across the full set as you scroll. Props: { content, theme }.
// Original copy + neutral placeholder media only.
import { useRef, useState, useEffect } from "react";
import { motion, useScroll, useTransform, useSpring, useReducedMotion } from "framer-motion";

export default function Section({ content, theme }) {
  const c = content || {};
  const title = c.title || "Create professional websites with complete creative control";

  const items = (c.items && c.items.length ? c.items : [
    { title: "Accelerate your start", text: "Get to a first draft fast with an AI site planner or professionally designed starter themes." },
    { title: "Pixel-perfect editing", text: "Design with total precision using drag-and-drop layout, global styles, and motion effects." },
    { title: "Engage and capture", text: "Turn visitors into customers with high-performance forms, popups, and lead-capture tools." },
    { title: "Dynamic by design", text: "Scale data-driven sites with dynamic content and smart display conditions for every visit." },
  ]);

  const rootRef = useRef(null);
  const [w, setW] = useState(1280);
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const ro = new ResizeObserver((e) => setW(e[0]?.borderBoxSize?.[0]?.inlineSize || el.clientWidth));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const narrow = w < 560, mid = w >= 560 && w < 1024;
  const reduce = useReducedMotion();

  // Measure the real scroll-container height (the device frame in a preview, the
  // window on a live site) so the pinned panel fits instead of assuming 100vh —
  // 100vh = the whole browser window, which is wrong inside a scaled device frame.
  const containerRef = useRef(null);
  const [vpH, setVpH] = useState(0);
  const [hasContainer, setHasContainer] = useState(false);
  useEffect(() => {
    const measure = () => {
      let el = rootRef.current ? rootRef.current.parentElement : null;
      let cont = null;
      while (el) {
        const s = getComputedStyle(el);
        if ((s.overflowY === "auto" || s.overflowY === "scroll") && el.clientHeight > 0) { cont = el; break; }
        el = el.parentElement;
      }
      containerRef.current = cont;
      setHasContainer(!!cont);
      setVpH(cont ? cont.clientHeight : window.innerHeight);
    };
    measure();
    window.addEventListener("resize", measure);
    return () => window.removeEventListener("resize", measure);
  }, [w]);
  const vh = vpH || 800;

  const padX = narrow ? 20 : mid ? 40 : 64;
  const gap = narrow ? 16 : 24;
  const cardW = narrow ? 250 : mid ? 340 : 420;
  const trackW = items.length * (cardW + gap) - gap;
  const shift = Math.max(0, trackW - w + padX * 2); // px the row must travel
  // Extra scroll after the row finishes travelling, so the last card sits fully
  // visible for a beat before the section unpins and scrolls away.
  const dwell = shift > 0 ? Math.round(vh * 0.5) : 0;
  const xEnd = shift + dwell > 0 ? shift / (shift + dwell) : 1;

  // Pinned scroll: vertical scroll through the section maps 1:1 to horizontal x.
  // Track the actual scroll container (a device frame in previews) when there is
  // one; otherwise the window (real sites). `hasContainer` forces a re-subscribe
  // once the container is detected after mount.
  const { scrollYProgress } = useScroll(
    hasContainer
      ? { target: rootRef, container: containerRef, offset: ["start start", "end end"] }
      : { target: rootRef, offset: ["start start", "end end"] },
  );
  const xRaw = useTransform(scrollYProgress, [0, xEnd], [0, -shift], { clamp: true });
  const x = useSpring(xRaw, { stiffness: 70, damping: 26, mass: 0.4 });

  const Heading = (
    <div style={{ maxWidth: 720 }}>
      <h2 style={{ fontFamily: theme.headingFont, fontWeight: 800, letterSpacing: "-0.02em", lineHeight: 1.05, fontSize: narrow ? 28 : mid ? 40 : 52, margin: 0, color: theme.textColor }}>{title}</h2>
    </div>
  );

  const Cards = items.map((it, i) => (
    <FeatureCard key={i} it={it} index={i} theme={theme} cardW={cardW} narrow={narrow} mid={mid} />
  ));

  // Reduced-motion only: native horizontal scroll instead of a pinned track.
  if (reduce) {
    return (
      <section ref={rootRef} style={{ background: theme.backgroundColor, color: theme.textColor, fontFamily: theme.bodyFont, padding: narrow ? "48px 0" : "88px 0", overflow: "hidden" }}>
        <div style={{ padding: `0 ${padX}px` }}>{Heading}</div>
        <div style={{ marginTop: narrow ? 28 : 56, display: "flex", gap, overflowX: "auto", padding: `0 ${padX}px 8px`, WebkitOverflowScrolling: "touch" }}>{Cards}</div>
      </section>
    );
  }

  // Pinned vertical→horizontal scroll on every breakpoint (desktop, iPad, mobile).
  return (
    <section ref={rootRef} style={{ position: "relative", height: `${vh + shift + dwell}px`, background: theme.backgroundColor, color: theme.textColor, fontFamily: theme.bodyFont }}>
      <div style={{ position: "sticky", top: 0, height: `${vh}px`, display: "flex", flexDirection: "column", justifyContent: narrow || mid ? "flex-start" : "center", paddingTop: narrow ? 40 : mid ? 56 : 64, paddingBottom: narrow ? 24 : 40, boxSizing: "border-box", overflow: "hidden" }}>
        <div style={{ padding: `0 ${padX}px` }}>{Heading}</div>
        <motion.div style={{ display: "flex", gap, marginTop: narrow ? 28 : 48, paddingLeft: padX, paddingRight: padX, width: "max-content", x }}>{Cards}</motion.div>
      </div>
    </section>
  );
}

function FeatureCard({ it, index, theme, cardW, narrow, mid }) {
  const accent = theme.accentColor;
  const line = theme.borderColor;
  const soft = theme.surfaceColor;
  const faint = theme.mutedTextColor;
  const radius = theme.radius || "18px";
  return (
    <div style={{ width: cardW, flexShrink: 0 }}>
      <div style={{ position: "relative", height: narrow ? 200 : mid ? 280 : 340, borderRadius: radius, overflow: "hidden", border: "1px solid " + line, background: "linear-gradient(135deg," + accent + "22 0%," + accent + "55 100%)", display: "grid", placeItems: "center" }}>
        <svg width="42" height="42" viewBox="0 0 24 24" fill="none" style={{ color: soft, opacity: 0.85 }}>
          <rect x="3" y="4" width="18" height="16" rx="3" stroke="currentColor" strokeWidth="1.4" />
          <circle cx="8.5" cy="9.5" r="1.8" fill="currentColor" />
          <path d="M3.5 16.5 8 12a1.6 1.6 0 0 1 2.3 0l3.4 3.4M13 14.2l2.4-2.4a1.6 1.6 0 0 1 2.3 0l2.7 2.7" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
        <Chip index={index} theme={theme} soft={soft} line={line} accent={accent} faint={faint} />
      </div>
      <h3 style={{ margin: narrow ? "14px 0 6px" : "22px 0 10px", fontFamily: theme.headingFont, fontWeight: 700, fontSize: narrow ? 19 : mid ? 22 : 26, color: theme.textColor }}>{it.title}</h3>
      <p style={{ margin: 0, fontSize: narrow ? 14.5 : 16, lineHeight: 1.6, color: faint, maxWidth: cardW - 20 }}>{it.text}</p>
    </div>
  );
}

// A rotating set of neutral, original placeholder "UI" chips (no brand assets).
function Chip({ index, theme, soft, line, accent, faint }) {
  const base = {
    position: "absolute", background: soft, borderRadius: 14,
    boxShadow: "0 12px 32px rgba(0,0,0,0.14)", border: "1px solid " + line,
    color: theme.textColor, fontFamily: theme.bodyFont,
  };
  const dot = { width: 30, height: 30, borderRadius: 999, background: accent, opacity: 0.55, flexShrink: 0 };

  if (index % 4 === 0) {
    return (
      <div style={{ ...base, left: 20, right: 20, bottom: 24, padding: 14, display: "flex", gap: 12, alignItems: "center" }}>
        <span style={dot} />
        <span style={{ fontSize: 14, lineHeight: 1.4, color: faint }}>Design wireframes for a premium storefront…</span>
      </div>
    );
  }
  if (index % 4 === 1) {
    return (
      <div style={{ ...base, right: 24, top: 24, width: 190, padding: 14 }}>
        {["Layout", "Shape", "Size"].map((k, r) => (
          <div key={k} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "6px 0", borderTop: r ? "1px solid " + line : 0 }}>
            <span style={{ fontSize: 12.5, color: faint }}>{k}</span>
            <span style={{ width: 46, height: 16, borderRadius: 6, background: accent, opacity: 0.35 }} />
          </div>
        ))}
      </div>
    );
  }
  if (index % 4 === 2) {
    return (
      <div style={{ ...base, left: 24, bottom: 24, width: 210, padding: 14 }}>
        <div style={{ fontSize: 13, fontWeight: 600 }}>Subscribers</div>
        <svg viewBox="0 0 180 60" width="100%" height="52" style={{ marginTop: 6 }}>
          <polyline points="4,48 46,40 92,44 138,14 176,6" fill="none" stroke={accent} strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" />
          <circle cx="176" cy="6" r="4.5" fill={accent} />
        </svg>
        <div style={{ fontSize: 12.5, color: faint }}>+140% monthly growth</div>
      </div>
    );
  }
  return (
    <div style={{ ...base, right: 24, bottom: 24, width: 200, padding: 14 }}>
      <div style={{ height: 70, borderRadius: 10, background: "linear-gradient(135deg," + accent + "22," + accent + "44)", marginBottom: 10 }} />
      <div style={{ fontSize: 14, fontWeight: 700 }}>Placeholder item</div>
      <div style={{ fontSize: 13, color: faint, marginTop: 2 }}>$38.99</div>
    </div>
  );
}

// Split intro + three feature cards with floating placeholder-UI chips.
// Props: { content, theme }. Original copy + neutral placeholder media only —
// no logos, no external images, no copied text.
import { useRef, useState, useEffect } from "react";
import { motion, useReducedMotion } from "framer-motion";

export default function Section({ content, theme }) {
  const c = content || {};
  const title = c.title || "Now in version 4!";
  const description = c.description ||
    "A new atomic foundation lets you style once with shared classes and variables, build reusable components, and ship lighter, fully responsive elements that load fast and scale with ease.";
  const cta = c.primaryButtonLabel || "Activate now";

  const items = (c.items && c.items.length ? c.items : [
    { title: "Transition at your own pace", text: "No need to rebuild anything. Start fresh and use new elements right alongside your existing ones." },
    { title: "Build reusable design systems", text: "Create scalable systems with classes, variables, and components so styles update everywhere at once." },
    { title: "Get unparalleled performance", text: "Ship cleaner code with a lighter CSS footprint and simpler markup for faster, smoother pages." },
  ]);

  const rootRef = useRef(null);
  const [w, setW] = useState(1280);
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const ro = new ResizeObserver(() => setW(el.clientWidth));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const narrow = w < 720;
  const mid = w >= 720 && w < 1040;
  const cols = narrow ? "1fr" : mid ? "1fr 1fr" : "1fr 1fr 1fr";

  const reduce = useReducedMotion();
  const accent = theme.accentColor;
  const line = theme.borderColor;
  const soft = theme.surfaceColor;
  const faint = theme.mutedTextColor;
  const radius = theme.radius || "18px";

  return (
    <section ref={rootRef} style={{
      background: theme.backgroundColor, color: theme.textColor, fontFamily: theme.bodyFont,
      padding: narrow ? "48px 20px" : "88px 64px",
    }}>
      <div style={{ maxWidth: 1240, margin: "0 auto" }}>
        {/* Split intro */}
        <div style={{
          display: "grid", gridTemplateColumns: narrow ? "1fr" : "1fr 1fr", gap: narrow ? 20 : 56,
          alignItems: "start",
        }}>
          <h2 style={{
            fontFamily: theme.headingFont, fontWeight: 800, letterSpacing: "-0.02em",
            lineHeight: 1.02, fontSize: narrow ? 40 : 60, margin: 0, color: theme.textColor,
          }}>{title}</h2>
          <div>
            <p style={{ margin: 0, fontSize: narrow ? 16 : 18, lineHeight: 1.6, color: faint }}>{description}</p>
            {cta && (
              <button type="button" style={{
                marginTop: 24, background: theme.textColor, color: theme.backgroundColor, border: 0,
                borderRadius: 10, padding: "13px 26px", fontWeight: 600, fontSize: 15, cursor: "pointer",
                fontFamily: theme.bodyFont,
              }}>{cta}</button>
            )}
          </div>
        </div>

        {/* Feature cards */}
        <div style={{ marginTop: narrow ? 40 : 72, display: "grid", gridTemplateColumns: cols, gap: 24 }}>
