  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const measure = () => {
      setW(el.clientWidth);
      let sp = el.parentElement;
      while (sp) { const oy = getComputedStyle(sp).overflowY; if (oy === "auto" || oy === "scroll") break; sp = sp.parentElement; }
      if (sp) { setAvail(Math.max(320, Math.round(sp.clientHeight))); }
