          <motion.p initial={reduce ? false : { opacity: 0, y: 16 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true, margin: "-40px" }} transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
            style={{ margin: 0, fontFamily: theme.headingFont, fontWeight: 600, letterSpacing: "-0.02em", lineHeight: 1.18, fontSize: topStack ? 24 : (w < 1120 ? 32 : 40), color: txt }}>{statement}</motion.p>
        </div>

