                <svg width="13" height="13" viewBox="0 0 24 24" fill="none"><path d="M5 12h14m0 0-6-6m6 6-6 6" stroke={onAccent} strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round" /></svg>
