// Big numbered services list. Each row reveals an accent fill, contrast text and
// a sliding arrow on hover/focus. Props: { content, theme } — every colour, font
// and radius comes from theme so a brand restyles it (dark + green, light, etc.).
import { useRef, useState, useEffect } from "react";
import { motion, useReducedMotion } from "framer-motion";

export default function Section({ content, theme }) {
  const c = content || {};
  const t = theme || {};
  const reduce = useReducedMotion();

  const items =
    Array.isArray(c.items) && c.items.length
      ? c.items
      : [
          { title: "Branding", href: "#" },
          { title: "UI/UX Design", href: "#" },
          { title: "Strategy", href: "#" },
          { title: "Design", href: "#" },
        ];
  const eyebrow = c.eyebrow || "Services";

  // Measure the section width (ResizeObserver works inside preview frames where
  // vw / matchMedia don't) and scale the row type + paddings from it.
  const ref = useRef(null);
  const [w, setW] = useState(1200);
  useEffect(() => {
    const el = ref.current;
    if (!el || typeof ResizeObserver === "undefined") return;
    const ro = new ResizeObserver((entries) => {
      for (const e of entries) setW(e.borderBoxSize && e.borderBoxSize[0] ? e.borderBoxSize[0].inlineSize : e.contentRect.width);
    });
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const compact = w < 720;

  const [active, setActive] = useState(-1);

  // Theme tokens (neutral fallbacks so the global Library reads light + on-brand
  // once a dark/green Style Guide is applied).
  const bg = t.backgroundColor || "#ffffff";
  const fg = t.textColor || "#111827";
  const accent = t.accentColor || "#2563eb";
  const onAccent = t.buttonTextColor || "#ffffff";
  const border = t.borderColor || "#e5e7eb";
  const muted = t.mutedTextColor || "#6b7280";
  const headingFont = t.headingFont || "inherit";
  const bodyFont = t.bodyFont || "inherit";
  const radius = t.radius || "14px";

  const nameSize = Math.round(Math.max(compact ? 26 : 34, Math.min(w * 0.075, 96)));
  const arrow = compact ? 26 : 38;
  const ease = [0.22, 1, 0.36, 1];
  // Padding from the MEASURED width (never vw — wrong in preview frames). Mobile
  // side padding is capped at 20px so it never feels cramped/oversized.
  const padX = w < 700 ? 20 : w < 1024 ? 40 : 60; // mobile 20 · iPad 40 · desktop 60
  const padY = w < 700 ? 64 : w < 1024 ? 80 : 96; // industry section rhythm

  return (
    <section
      ref={ref}
      style={{
        background: bg,
        color: fg,
        fontFamily: bodyFont,
        padding: `${padY}px ${padX}px`,
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: compact ? 28 : 52 }}>
        <span aria-hidden="true" style={{ width: 8, height: 8, borderRadius: 999, background: accent, display: "inline-block" }} />
        <span style={{ fontSize: 15, fontWeight: 600, letterSpacing: "0.01em" }}>{eyebrow}</span>
      </div>

      <ul role="list" style={{ listStyle: "none", margin: 0, padding: 0 }}>
        {items.map((it, i) => {
          const on = active === i;
          const num = String(i + 1).padStart(2, "0");
          const last = i === items.length - 1;
          return (
            <li
              key={i}
              style={{
                borderTop: `1px solid ${border}`,
                ...(last ? { borderBottom: `1px solid ${border}` } : {}),
              }}
            >
              <motion.a
                href={it.href || "#"}
                onMouseEnter={() => setActive(i)}
                onMouseLeave={() => setActive(-1)}
                onFocus={() => setActive(i)}
                onBlur={() => setActive(-1)}
                animate={{
                  backgroundColor: on ? accent : "rgba(0,0,0,0)",
                  color: on ? onAccent : fg,
                  borderRadius: on ? parseInt(radius, 10) || 14 : 0,
                }}
                transition={reduce ? { duration: 0 } : { duration: 0.3, ease }}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: compact ? 14 : 28,
                  textDecoration: "none",
                  color: fg,
                  padding: compact ? "16px 14px" : "20px 28px",
                }}
              >
                <span
                  style={{
                    flexShrink: 0,
                    width: compact ? 22 : 36,
                    fontFamily: bodyFont,
                    fontSize: compact ? 12 : 14,
                    fontVariantNumeric: "tabular-nums",
                    color: on ? onAccent : muted,
                  }}
                >
                  {num}
                </span>
                <span
                  style={{
                    flex: 1,
                    minWidth: 0,
                    fontFamily: headingFont,
                    fontWeight: 600,
                    lineHeight: 1.02,
                    letterSpacing: "-0.02em",
                    fontSize: nameSize,
                  }}
                >
                  {it.title}
                </span>
                <motion.span
                  aria-hidden="true"
                  animate={{ x: on && !reduce ? 8 : 0 }}
                  transition={reduce ? { duration: 0 } : { duration: 0.3, ease }}
                  style={{ flexShrink: 0, display: "grid", placeItems: "center" }}
                >
                  <svg width={arrow} height={arrow} viewBox="0 0 24 24" fill="none">
                    <path d="M5 12h14M13 6l6 6-6 6" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" />
                  </svg>
                </motion.span>
              </motion.a>
            </li>
          );
        })}
      </ul>
    </section>
  );
}

