// Hero carousel (media) — full-bleed background per slide with eyebrow, oversized
// headline and a CTA, plus a row of topic tabs. Auto-advances (a progress line
// fills under the active tab); clicking a tab switches BOTH the background and
// the copy. Props: { content, theme }. Give each slide a real photo via
// item.image (recommended 1600×900); without one it falls back to a themeable
// accent gradient. Accent + fonts are theme-driven; the dark media surface +
// white text are intentional to a hero-over-image.
import { useRef, useState, useEffect } from "react";
import { motion, AnimatePresence, useReducedMotion } from "framer-motion";

const DURATION = 6000;

const DEFAULTS = [
  { text: "Intelligence", title: "Put AI to work across every team" },
  { text: "Strategy", title: "The mid-year outlook leaders plan around" },
  { text: "Retail", title: "Pricing built for both people and machines" },
  { text: "Partnerships", title: "Scaling what comes next in the cloud" },
];

export default function Section({ content, theme }) {
  const c = content || {};
  const t = theme || {};
  const reduce = useReducedMotion();

  const cta = c.primaryButtonLabel || "Read more";
  const src = Array.isArray(c.items) && c.items.length ? c.items : DEFAULTS;
  const slides = src.map((s, i) => ({
    label: s.text || DEFAULTS[i % DEFAULTS.length].text || `Slide ${i + 1}`,
    title: s.title || DEFAULTS[i % DEFAULTS.length].title || "A headline for this slide",
    href: s.href || "#",
    image: s.image || s.imageUrl || "",
  }));

  const ref = useRef(null);
  const [w, setW] = useState(1200);
  useEffect(() => {
    const el = ref.current;
    if (!el || typeof ResizeObserver === "undefined") return;
    const ro = new ResizeObserver((entries) => {
      for (const e of entries) setW(e.borderBoxSize && e.borderBoxSize[0] ? e.borderBoxSize[0].inlineSize : e.contentRect.width);
    });
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const compact = w < 700;

  const [active, setActive] = useState(0);
  useEffect(() => {
    if (reduce || slides.length < 2) return;
    const id = setTimeout(() => setActive((a) => (a + 1) % slides.length), DURATION);
    return () => clearTimeout(id);
  }, [active, reduce, slides.length]);

  const accent = t.accentColor || "#2563eb";
  const headingFont = t.headingFont || "inherit";
  const bodyFont = t.bodyFont || "inherit";
  // Media hero: text sits on a dark image/gradient, so it stays light for
  // legibility (the accent still drives the fallback gradient hue + progress).
  const fg = "#ffffff";
  const muted = "rgba(255,255,255,0.66)";
  const line = "rgba(255,255,255,0.28)";

  const padX = w < 700 ? 20 : w < 1024 ? 40 : 60; // mobile 20 · iPad 40 · desktop 60
  const titleSize = Math.round(Math.max(compact ? 34 : 44, Math.min(w * 0.05, 84)));
  const ease = [0.22, 1, 0.36, 1];
  const cur = slides[active] || slides[0];

  const backdrop = (s) =>
    s.image
      ? `linear-gradient(90deg, rgba(0,0,0,0.6), rgba(0,0,0,0.25) 55%, rgba(0,0,0,0.1)), url("${s.image}") center / cover no-repeat`
      : `linear-gradient(${118 + active * 26}deg, ${accent}, #0b0b12 82%)`;

  return (
    <section
      ref={ref}
      style={{
        position: "relative",
        overflow: "hidden",
        color: fg,
        fontFamily: bodyFont,
        minHeight: "clamp(560px, 84vh, 920px)",
        display: "flex",
        flexDirection: "column",
        background: "#0b0b12",
      }}
    >
      {/* Full-bleed backdrop, crossfading per slide */}
      <AnimatePresence initial={false}>
        <motion.div
          key={active}
          aria-hidden="true"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: reduce ? 0 : 0.7, ease }}
          style={{ position: "absolute", inset: 0, background: backdrop(cur) }}
        />
      </AnimatePresence>
      {/* Bottom scrim so the tab row always reads */}
      <div aria-hidden="true" style={{ position: "absolute", inset: 0, background: "linear-gradient(to top, rgba(0,0,0,0.45), transparent 38%)", pointerEvents: "none" }} />
      {/* Faint hint only when the active slide has no image yet */}
      {!cur.image && (
        <div aria-hidden="true" style={{ position: "absolute", right: padX, bottom: compact ? 120 : 120, display: "flex", alignItems: "center", gap: 8, color: "rgba(255,255,255,0.55)", fontSize: 12.5 }}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none"><rect x="3" y="4" width="18" height="16" rx="2.5" stroke="currentColor" strokeWidth="1.6" /><circle cx="8.5" cy="9.5" r="1.6" stroke="currentColor" strokeWidth="1.6" /><path d="M5 17l4.5-4.5 3 3L16 12l3 3" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" /></svg>
          Add a background image
        </div>
      )}

      {/* Foreground copy */}
      <div style={{ position: "relative", flex: 1, display: "flex", alignItems: "center", padding: `${compact ? 88 : 120}px ${padX}px 0` }}>
        <AnimatePresence mode="wait">
          <motion.div
            key={active}
            initial={reduce ? { opacity: 0 } : { opacity: 0, y: 18 }}
            animate={{ opacity: 1, y: 0 }}
            exit={reduce ? { opacity: 0 } : { opacity: 0, y: -12 }}
            transition={{ duration: reduce ? 0 : 0.5, ease }}
            style={{ width: "100%", maxWidth: compact ? "100%" : 900 }}
          >
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}>
              <span aria-hidden="true" style={{ width: 8, height: 8, borderRadius: 999, background: accent, display: "inline-block" }} />
              <span style={{ fontSize: 14, fontWeight: 600, letterSpacing: "0.02em", textTransform: "uppercase" }}>{cur.label}</span>
            </div>
            <h1 style={{ margin: 0, color: fg, fontFamily: headingFont, fontWeight: 600, letterSpacing: "-0.03em", lineHeight: 1.04, fontSize: titleSize, maxWidth: compact ? "100%" : Math.min(860, Math.round(w * 0.66)), textWrap: "balance", WebkitTextWrap: "balance" }}>
              {cur.title}
            </h1>
            <a href={cur.href} style={{ marginTop: 28, display: "inline-flex", alignItems: "center", gap: 12, textDecoration: "none", color: fg, fontFamily: bodyFont, fontSize: 14, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase" }}>
              {cta}
              <svg width="34" height="14" viewBox="0 0 34 14" fill="none" aria-hidden="true">
                <path d="M0 7h31M26 2l6 5-6 5" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" />
              </svg>
            </a>
          </motion.div>
        </AnimatePresence>
      </div>

      {/* Tabs + auto-advance progress */}
      <div style={{ position: "relative", padding: `0 ${padX}px ${compact ? 26 : 40}px`, display: "flex", alignItems: "flex-end", gap: 16 }}>
        <div style={{ flex: 1, display: "grid", gridTemplateColumns: compact ? "1fr" : `repeat(${slides.length}, 1fr)`, gap: compact ? 8 : 24 }}>
          {slides.map((s, i) => {
            const on = i === active;
            if (compact && !on) return null; // mobile: only the active tab label
            return (
              <button
                key={i}
                type="button"
                onClick={() => setActive(i)}
                aria-current={on ? "true" : undefined}
                style={{
                  appearance: "none",
                  border: 0,
                  background: "transparent",
                  textAlign: "left",
                  cursor: "pointer",
                  padding: "12px 0 0",
                  fontFamily: bodyFont,
                  fontSize: compact ? 14 : 16,
                  fontWeight: 600,
                  color: on ? fg : muted,
                  borderTop: `2px solid ${line}`,
                  position: "relative",
                  whiteSpace: "nowrap",
                }}
              >
                {on && (
                  <motion.span
                    key={active}
                    aria-hidden="true"
                    initial={{ scaleX: reduce ? 1 : 0 }}
                    animate={{ scaleX: 1 }}
                    transition={reduce ? { duration: 0 } : { duration: DURATION / 1000, ease: "linear" }}
                    style={{ position: "absolute", top: -2, left: 0, right: 0, height: 2, background: accent, transformOrigin: "left center" }}
                  />
                )}
                {s.label}
              </button>
            );
          })}
        </div>

        <div style={{ display: "grid", justifyItems: "center", gap: 8, color: muted, flexShrink: 0 }}>
          <span style={{ fontSize: 12 }}>Scroll</span>
          <motion.span
            aria-hidden="true"
            animate={reduce ? {} : { y: [0, 5, 0] }}
            transition={reduce ? {} : { duration: 1.6, repeat: Infinity, ease: "easeInOut" }}
            style={{ display: "grid", placeItems: "center", width: 40, height: 40, borderRadius: 999, border: `1px solid ${line}` }}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none"><path d="M6 9l6 6 6-6" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round" /></svg>
          </motion.span>
        </div>
      </div>
    </section>
  );
}

