// Distinct content + layout per menu. No brand names, no repeated labels.
const MENUS = {
  products: {
    layout: "rail",
    tabs: ["For teams", "For customers"],
    columns: [
      {
        eyebrow: "Products",
        featured: [
          { title: "Service Suite", desc: "Unified service platform", children: ["Service management", "Enterprise service", "Asset management"] },
