    ],
  },
  ai: {
    layout: "three",
    columns: [
      { eyebrow: "Platform", featured: [{ title: "AI Assistant", desc: "Automate, assist and scale service", iconLinks: ["For internal teams", "For customer service"] }] },
      { eyebrow: "Capabilities", links: ["AI agent for employees", "AI copilot for agents", "AI insights for leaders"], cta: "See it in action", divider: true },
      { eyebrow: "Trending", card: { title: "New AI features", desc: "See the latest AI-driven tools.", tone: "dark" }, divider: true },
    ],
  },
  resources: {
    layout: "links",
    columns: [
      { eyebrow: "Learn & connect", twoCol: [["Resource center", "Events", "Webinars", "Guides blog"], ["Customer stories", "Community", "App marketplace", "Developers"]] },
      { eyebrow: "Support", links: ["Support", "Services", "Training"], icons: true, divider: true },
      { eyebrow: "Company", links: ["About us", "Partners", "Newsroom"], icons: true },
      { eyebrow: "Trending", card: { title: "Virtual event 2026", desc: "Service transformation made easy", tone: "light" }, divider: true },
    ],
  },
};

export default function Section({ content, theme }) {
  const c = content || {};
  const t = theme || {};
  const reduce = useReducedMotion();

  const rootRef = useRef(null);
  const [w, setW] = useState(1440);
  const [mega, setMega] = useState(-1);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [mobileSub, setMobileSub] = useState(-1);
  const [activeTab, setActiveTab] = useState(0);

  useEffect(() => {
    const el = rootRef.current;
    if (!el || typeof ResizeObserver === "undefined") return;
    const ro = new ResizeObserver((entries) => {
      const e = entries[0];
      setW(e.borderBoxSize && e.borderBoxSize[0] ? e.borderBoxSize[0].inlineSize : e.contentRect.width);
    });
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

  const desktop = w >= 1024;
  const tablet = w >= 768 && w < 1024;
  const mobile = w < 768;
  const compact = !desktop;

  useEffect(() => { if (desktop) { setDrawerOpen(false); setMobileSub(-1); } else setMega(-1); }, [desktop]);
  useEffect(() => { if (!drawerOpen) setMobileSub(-1); }, [drawerOpen]);
  useEffect(() => {
    if (!compact) return;
    document.body.style.overflow = drawerOpen ? "hidden" : "";
    return () => { document.body.style.overflow = ""; };
  }, [drawerOpen, compact]);
  useEffect(() => {
    const onKey = (e) => { if (e.key === "Escape") { setMega(-1); setDrawerOpen(false); } };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  const KINDS = ["products", "ai", "resources"];
  let menuCount = -1;
  const nav = Array.isArray(c.items) && c.items.length
    ? c.items.map((item) => {
        const isMenu = item.text === "menu" || item.menu === true;
        if (isMenu) menuCount += 1;
        return { label: item.title || item.label || "Menu", href: item.href || "#", menu: isMenu, star: item.icon === "star" || item.star === true, kind: isMenu ? KINDS[menuCount % KINDS.length] : null };
      })
    : DEFAULT_NAV;

  const brand = c.title || "Your Company";
  const primary = c.primaryButtonLabel || "Try it free";
  const secondary = c.secondaryButtonLabel || "Demo";

  const bg = t.backgroundColor || "#ffffff";
  const fg = t.textColor || "#1f2329";
  const muted = t.mutedTextColor || "#5f6675";
  const border = t.borderColor || "#e7e9f2";
  const surface = t.surfaceColor || "#f5f6ff";
  const accent = t.accentColor || "#8a10e8";
  const btnBg = t.buttonBgColor || accent;
  const btnFg = t.buttonTextColor || "#ffffff";
  const dark = t.primaryColor || "#0b1220";
  const bodyFont = t.bodyFont || "Inter, system-ui, -apple-system, 'Segoe UI', sans-serif";
  const headingFont = t.headingFont || bodyFont;

  const padX = mobile ? 20 : tablet ? 40 : 60;
  const headerHeight = mobile ? 72 : 86;
  const ease = [0.22, 1, 0.36, 1];
  const closeAll = () => { setMega(-1); setDrawerOpen(false); setMobileSub(-1); };

  const Logo = () => (
    <a href="#" aria-label={`${brand} home`} style={{ display: "inline-flex", alignItems: "center", gap: 9, textDecoration: "none", color: fg, minWidth: 0, maxWidth: mobile ? 200 : 240 }}>
      <span aria-hidden="true" style={{ width: 26, height: 26, borderRadius: "42% 58% 52% 48%", background: "conic-gradient(from 210deg, #22c55e, #06b6d4, #8b5cf6, #f97316, #22c55e)", display: "inline-block", flexShrink: 0 }} />
      <span style={{ fontFamily: headingFont, fontSize: 20, lineHeight: 1, letterSpacing: "-0.02em", fontWeight: 700, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{brand}</span>
    </a>
  );
  const StarIcon = () => (<svg width="18" height="18" viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="M12 2c.55 4.95 4.45 8.85 9.4 9.4-4.95.55-8.85 4.45-9.4 9.4-.55-4.95-4.45-8.85-9.4-9.4C7.55 10.85 11.45 6.95 12 2Z" fill={accent} /></svg>);
  const ChevronDown = ({ open }) => (<svg width="16" height="16" viewBox="0 0 24 24" fill="none" aria-hidden="true" style={{ transform: open ? "rotate(180deg)" : "none", transition: "transform 180ms ease" }}><path d="M6 9l6 6 6-6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>);
  const ChevronRight = ({ size = 18 }) => (<svg width={size} height={size} viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="M9 6l6 6-6 6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>);
  const Arrow = ({ size = 15 }) => (<svg width={size} height={size} viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d="M5 12h14M13 6l6 6-6 6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>);
  const LinkIcon = () => (<svg width="18" height="18" viewBox="0 0 24 24" fill="none" aria-hidden="true"><rect x="3.5" y="4.5" width="17" height="15" rx="3" stroke="currentColor" strokeWidth="1.7" /><path d="M8 9h8M8 13h5" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" /></svg>);
  const PrimaryButton = ({ full = false }) => (<a href="#" style={{ display: "inline-flex", alignItems: "center", justifyContent: "center", width: full ? "100%" : "auto", minHeight: 46, padding: full ? "0 22px" : "0 26px", borderRadius: 8, background: btnBg, color: btnFg, textDecoration: "none", fontFamily: bodyFont, fontSize: 16, fontWeight: 700, whiteSpace: "nowrap" }}>{primary}</a>);
  const Eyebrow = ({ children }) => (<p style={{ margin: "0 0 26px", color: muted, fontSize: 13, fontWeight: 800, letterSpacing: "0.06em", textTransform: "uppercase" }}>{children}</p>);
  const iconBtn = { appearance: "none", border: 0, background: "transparent", cursor: "pointer", color: fg, padding: 0, display: "grid", placeItems: "center" };

  // A trending promo card (image placeholder + title/desc). tone dark|light.
  const TrendCard = ({ card }) => {
    const isDark = card.tone !== "light";
    const cbg = isDark ? "linear-gradient(150deg, #0b1220 0%, #0b1b34 55%, #103a6b 100%)" : `linear-gradient(150deg, ${surface}, #ece9ff)`;
    const ctext = isDark ? "#ffffff" : fg;
    const csub = isDark ? "rgba(255,255,255,0.72)" : muted;
    return (
      <a href="#" style={{ display: "block", position: "relative", minHeight: 220, borderRadius: 16, overflow: "hidden", background: cbg, color: ctext, textDecoration: "none", boxSizing: "border-box" }}>
        <div style={{ padding: 22 }}>
          <p style={{ margin: 0, fontSize: 16, fontWeight: 800 }}>{card.title}</p>
          <p style={{ margin: "6px 0 0", fontSize: 14, lineHeight: 1.4, color: csub, maxWidth: 240 }}>{card.desc}</p>
        </div>
        <div style={{ position: "absolute", inset: "auto 16px 16px 16px", height: 96, borderRadius: 10, background: isDark ? "rgba(255,255,255,0.06)" : "#ffffff", border: `1px solid ${isDark ? "rgba(255,255,255,0.14)" : border}`, display: "grid", placeItems: "center", color: isDark ? "rgba(255,255,255,0.5)" : muted }}>
          <div style={{ display: "grid", justifyItems: "center", gap: 4 }}>
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none"><rect x="3" y="4" width="18" height="16" rx="3" stroke="currentColor" strokeWidth="1.6" /><circle cx="8.5" cy="9.5" r="1.6" stroke="currentColor" strokeWidth="1.6" /><path d="M5 17l4.5-4.5 3 3L16 12l3 3" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" /></svg>
            <span style={{ fontSize: 11 }}>Add an image</span>
          </div>
        </div>
      </a>
    );
  };

  // One desktop column (featured items / link list / two-col / cta / card).
  const Column = ({ col }) => (
    <section style={{ borderLeft: col.divider ? `1px solid ${border}` : "none", paddingLeft: col.divider ? 30 : 0 }}>
      <Eyebrow>{col.eyebrow}</Eyebrow>
      {col.featured && (
        <div style={{ display: "grid", gap: 24 }}>
          {col.featured.map((p) => (
            <div key={p.title}>
              <a href="#" style={{ display: "inline-flex", alignItems: "center", gap: 8, textDecoration: "none", color: fg, fontSize: 17, fontWeight: 800 }}>{p.title}<ChevronRight size={16} /></a>
              <p style={{ margin: "6px 0 14px", color: muted, fontSize: 14, lineHeight: 1.35 }}>{p.desc}</p>
              {(p.children || []).length > 0 && (
                <div style={{ display: "grid", gap: 14 }}>
                  {p.children.map((ch, i) => (
                    <a key={ch} href="#" style={{ display: "grid", gridTemplateColumns: "30px 1fr", gap: 12, alignItems: "start", textDecoration: "none", color: fg, fontSize: 14.5, lineHeight: 1.3, fontWeight: 500 }}>
                      <span style={{ color: fg }}><SmallIcon type={i} /></span>{ch}
                    </a>
                  ))}
                </div>
              )}
              {(p.iconLinks || []).length > 0 && (
                <div style={{ display: "grid", gap: 16 }}>
                  {p.iconLinks.map((ch, i) => (
                    <a key={ch} href="#" style={{ display: "inline-flex", alignItems: "center", gap: 12, textDecoration: "none", color: fg, fontSize: 15, fontWeight: 500 }}>
                      <span style={{ display: "grid", placeItems: "center", width: 32, height: 32, borderRadius: 9, background: surface }}><SmallIcon type={i} /></span>{ch}
                    </a>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
      {col.twoCol && (
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "18px 24px" }}>
          {col.twoCol.flat().map((l) => <ResLink key={l} label={l} />)}
        </div>
      )}
      {col.links && (
        <div style={{ display: "grid", gap: col.icons ? 18 : 20 }}>
          {col.links.map((l) => col.icons ? <ResLink key={l} label={l} /> : <a key={l} href="#" style={{ textDecoration: "none", color: fg, fontSize: 14.5, fontWeight: 500 }}>{l}</a>)}
          {col.cta && <a href="#" style={{ display: "inline-flex", alignItems: "center", gap: 6, marginTop: 8, textDecoration: "none", color: accent, fontSize: 14.5, fontWeight: 800 }}>{col.cta}<Arrow /></a>}
        </div>
      )}
      {col.card && <TrendCard card={col.card} />}
    </section>
  );

  const ResLink = ({ label }) => {
    const badge = /webinars/i.test(label);
    return (
      <a href="#" style={{ display: "inline-flex", alignItems: "center", gap: 12, textDecoration: "none", color: fg, fontSize: 14.5, fontWeight: 500 }}>
        <span style={{ color: muted, display: "grid", placeItems: "center" }}><LinkIcon /></span>
        {label}
        {badge && <span style={{ fontSize: 10, fontWeight: 800, letterSpacing: "0.04em", color: accent, background: `${accent}1a`, borderRadius: 5, padding: "2px 6px", textTransform: "uppercase" }}>New</span>}
      </a>
    );
  };

  const SmallIcon = ({ type }) => {
    const d = type === 0
      ? "M12 8.4a3.6 3.6 0 1 0 0 7.2 3.6 3.6 0 0 0 0-7.2Zm8.2 3.6c0-.48-.05-.95-.15-1.4l2-1.55-2-3.46-2.35.95a8.5 8.5 0 0 0-2.43-1.4L15 2h-4l-.27 2.64a8.5 8.5 0 0 0-2.43 1.4l-2.35-.95-2 3.46 2 1.55A7 7 0 0 0 5.8 12c0 .48.05.95.15 1.4l-2 1.55 2 3.46 2.35-.95a8.5 8.5 0 0 0 2.43 1.4L11 22h4l.27-2.64a8.5 8.5 0 0 0 2.43-1.4l2.35.95 2-3.46-2-1.55c.1-.45.15-.92.15-1.4Z"
      : type === 1 ? "M12 3a7 7 0 0 0-7 7v4a3 3 0 0 0 3 3h1v-6H7v-1a5 5 0 0 1 10 0v1h-2v6h1a3 3 0 0 0 3-3v-4a7 7 0 0 0-7-7Z"
      : "M3.8 7.2h6l1.8 2.2h8.6v9.1a2 2 0 0 1-2 2H5.8a2 2 0 0 1-2-2V7.2Z";
    return (<svg width="22" height="22" viewBox="0 0 24 24" fill="none" aria-hidden="true"><path d={d} stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round" /></svg>);
  };

  const MegaMenu = () => {
    const item = nav[mega];
    const menu = item ? MENUS[item.kind] : null;
    return (
      <AnimatePresence initial={false}>
        {desktop && mega >= 0 && menu && (
          <motion.div key={"mega" + mega} role="region" aria-label={`${item.label} menu`}
            initial={reduce ? { opacity: 0 } : { opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }} exit={reduce ? { opacity: 0 } : { opacity: 0, y: -8 }} transition={{ duration: reduce ? 0 : 0.22, ease }}
            style={{ position: "relative", zIndex: 1 }}>
            <div style={{ maxWidth: 1680, margin: "0 auto", padding: `14px ${padX}px 12px` }}>
              <div style={{ borderRadius: 26, background: "linear-gradient(90deg, rgba(205,246,255,0.6), #ffffff 26%, rgba(245,242,255,0.9))", boxShadow: "0 30px 80px rgba(15,23,42,0.16)", border: `1px solid ${border}`, padding: 16, overflow: "hidden" }}>
                {menu.layout === "rail" ? (
                  <div style={{ background: bg, borderRadius: 16, display: "grid", gridTemplateColumns: w < 1280 ? "230px 1fr" : "260px 1fr", overflow: "hidden" }}>
                    <aside style={{ padding: "24px 18px", borderRight: `1px solid ${border}` }}>
                      <div style={{ display: "grid", gap: 10 }}>
                        {menu.tabs.map((tab, i) => (
                          <button key={tab} type="button" onClick={() => setActiveTab(i)}
                            style={{ appearance: "none", border: 0, background: activeTab === i ? "#202128" : "transparent", color: activeTab === i ? "#fff" : fg, minHeight: 50, borderRadius: 8, padding: "0 16px", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8, cursor: "pointer", fontFamily: bodyFont, fontSize: 15, fontWeight: 700, textAlign: "left" }}>
                            {tab}<ChevronRight size={18} />
                          </button>
                        ))}
                      </div>
                    </aside>
                    <div style={{ padding: "30px 30px 26px", display: "grid", gridTemplateColumns: "1.1fr 1fr 0.95fr 1.05fr", gap: 26 }}>
                      {menu.columns.map((col, i) => <Column key={i} col={i === 1 || i === 2 ? { ...col, divider: true } : col} />)}
                    </div>
                  </div>
                ) : (
                  <div style={{ background: bg, borderRadius: 16, padding: "34px 34px 30px", display: "grid", gridTemplateColumns: menu.layout === "three" ? "1.1fr 1fr 1.15fr" : "1.5fr 0.9fr 0.9fr 1.15fr", gap: 30 }}>
                    {menu.columns.map((col, i) => <Column key={i} col={col} />)}
                  </div>
                )}
                <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "16px 30px 4px", color: fg, fontSize: 14 }}>
                  <span style={{ width: 24, height: 24, borderRadius: 999, background: "#050505", color: "#fff", display: "grid", placeItems: "center", fontSize: 10, fontWeight: 900 }}>★</span>
                  <span style={{ color: "#f59e0b", letterSpacing: 1 }}>★★★★★</span>
                  <span style={{ color: muted }}>Trusted by teams worldwide</span>
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    );
  };

  // Drawer sub-screen: the same menu's content, stacked.
  const DrawerSub = ({ kind }) => {
    const menu = MENUS[kind];
    if (!menu) return null;
    return (
      <div>
        {menu.tabs && (
          <div style={{ display: "grid", gap: 10, marginBottom: 20 }}>
            {menu.tabs.map((tab, i) => (
              <button key={tab} type="button" onClick={() => setActiveTab(i)} style={{ border: 0, minHeight: 52, borderRadius: 12, background: activeTab === i ? dark : surface, color: activeTab === i ? "#fff" : fg, padding: "0 16px", display: "flex", alignItems: "center", justifyContent: "space-between", fontFamily: bodyFont, fontSize: 16, fontWeight: 700, cursor: "pointer" }}>{tab}<ChevronRight /></button>
            ))}
          </div>
        )}
        {menu.columns.filter((col) => !col.card).map((col, ci) => (
          <section key={ci} style={{ borderTop: ci ? `1px solid ${border}` : "none", paddingTop: ci ? 20 : 0, marginTop: ci ? 20 : 0 }}>
            <Eyebrow>{col.eyebrow}</Eyebrow>
            {col.featured && col.featured.map((p) => (
              <div key={p.title} style={{ marginBottom: 16 }}>
                <a href="#" onClick={closeAll} style={{ display: "inline-flex", alignItems: "center", gap: 8, color: fg, textDecoration: "none", fontSize: 18, fontWeight: 800 }}>{p.title}<ChevronRight size={16} /></a>
                <p style={{ margin: "4px 0 12px", color: muted, fontSize: 14 }}>{p.desc}</p>
                {[...(p.children || []), ...(p.iconLinks || [])].map((ch) => (
                  <a key={ch} href="#" onClick={closeAll} style={{ minHeight: 42, display: "flex", alignItems: "center", color: fg, textDecoration: "none", fontSize: 16, fontWeight: 500 }}>{ch}</a>
                ))}
              </div>
            ))}
            {(col.twoCol ? col.twoCol.flat() : col.links || []).map((l) => (
              <a key={l} href="#" onClick={closeAll} style={{ minHeight: 44, display: "flex", alignItems: "center", justifyContent: "space-between", color: fg, textDecoration: "none", fontSize: 16, fontWeight: 500 }}>{l}<ChevronRight size={16} /></a>
            ))}
            {col.cta && <a href="#" onClick={closeAll} style={{ display: "inline-flex", alignItems: "center", gap: 6, marginTop: 8, color: accent, textDecoration: "none", fontSize: 16, fontWeight: 800 }}>{col.cta}<Arrow /></a>}
          </section>
        ))}
      </div>
    );
  };

  const Drawer = () => (
    <AnimatePresence>
      {compact && drawerOpen && (
        <motion.div role="dialog" aria-modal="true" aria-label="Menu" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} transition={{ duration: reduce ? 0 : 0.18 }}
          style={{ position: "fixed", inset: 0, zIndex: 80, background: bg, color: fg, display: "flex", flexDirection: "column", fontFamily: bodyFont }}>
          <div style={{ height: headerHeight, padding: `0 ${padX}px`, borderBottom: `1px solid ${border}`, display: "flex", alignItems: "center", justifyContent: "space-between", gap: 16, flexShrink: 0 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12, minWidth: 0 }}>
              {mobileSub >= 0 && (
                <button type="button" aria-label="Back" onClick={() => setMobileSub(-1)} style={{ ...iconBtn, width: 42, height: 42, borderRadius: 12, border: `1px solid ${border}`, background: surface }}>
                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M15 6l-6 6 6 6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>
                </button>
              )}
              <Logo />
            </div>
            <button type="button" aria-label="Close menu" onClick={closeAll} style={{ ...iconBtn, width: 44, height: 44, borderRadius: 12, border: `1px solid ${border}`, background: surface }}>
              <svg width="23" height="23" viewBox="0 0 24 24" fill="none"><path d="M6 6l12 12M18 6L6 18" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /></svg>
            </button>
          </div>
          <div style={{ flex: 1, minHeight: 0, overflowY: "auto", padding: `20px ${padX}px 30px` }}>
            <AnimatePresence mode="wait" initial={false}>
              {mobileSub < 0 ? (
                <motion.div key="root" initial={reduce ? { opacity: 0 } : { opacity: 0, x: -16 }} animate={{ opacity: 1, x: 0 }} exit={reduce ? { opacity: 0 } : { opacity: 0, x: -16 }} transition={{ duration: reduce ? 0 : 0.2, ease }}>
                  {nav.map((item, index) => item.menu ? (
                    <button key={item.label} type="button" onClick={() => setMobileSub(index)} style={{ width: "100%", border: 0, background: "transparent", color: fg, minHeight: 60, padding: 0, display: "flex", alignItems: "center", justifyContent: "space-between", gap: 16, cursor: "pointer", fontFamily: bodyFont, fontSize: 22, fontWeight: 600, textAlign: "left" }}>
                      <span style={{ display: "inline-flex", alignItems: "center", gap: 10 }}>{item.star && <StarIcon />}{item.label}</span><ChevronRight />
                    </button>
                  ) : (
                    <a key={item.label} href={item.href || "#"} onClick={closeAll} style={{ minHeight: 60, display: "flex", alignItems: "center", color: fg, textDecoration: "none", fontSize: 22, fontWeight: 600 }}>{item.label}</a>
                  ))}
                  <div style={{ height: 1, background: border, margin: "18px 0" }} />
                  {[secondary, "Contact sales", "Log in"].map((l) => (
                    <a key={l} href="#" onClick={closeAll} style={{ minHeight: 52, display: "flex", alignItems: "center", justifyContent: "space-between", color: fg, textDecoration: "none", fontSize: 18, fontWeight: 500 }}>{l}<ChevronRight size={16} /></a>
                  ))}
                </motion.div>
              ) : (
                <motion.div key="sub" initial={reduce ? { opacity: 0 } : { opacity: 0, x: 16 }} animate={{ opacity: 1, x: 0 }} exit={reduce ? { opacity: 0 } : { opacity: 0, x: 16 }} transition={{ duration: reduce ? 0 : 0.2, ease }}>
                  <p style={{ margin: "0 0 18px", color: muted, fontSize: 13, fontWeight: 900, letterSpacing: "0.08em", textTransform: "uppercase" }}>{nav[mobileSub]?.label}</p>
                  <DrawerSub kind={nav[mobileSub]?.kind} />
                </motion.div>
              )}
            </AnimatePresence>
          </div>
          {mobileSub < 0 && (
            <div style={{ padding: `16px ${padX}px 22px`, borderTop: `1px solid ${border}`, flexShrink: 0, background: bg }}><PrimaryButton full /></div>
          )}
        </motion.div>
      )}
    </AnimatePresence>
  );

  return (
    <header ref={rootRef} style={{ position: "relative", zIndex: 50, background: bg, color: fg, fontFamily: bodyFont, borderBottom: `1px solid ${border}` }}>
      <div style={{ minHeight: headerHeight, maxWidth: 1920, margin: "0 auto", padding: `0 ${padX}px`, display: "flex", alignItems: "center", justifyContent: "space-between", gap: 28, boxSizing: "border-box" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 40, minWidth: 0 }}>
          <Logo />
          {desktop && (
            <nav aria-label="Primary" style={{ display: "flex", alignItems: "center", gap: 30 }}>
              {nav.map((item, index) => item.menu ? (
                <button key={item.label} type="button" aria-expanded={mega === index} onClick={() => setMega(mega === index ? -1 : index)}
                  style={{ appearance: "none", border: 0, background: "transparent", color: mega === index ? accent : fg, display: "inline-flex", alignItems: "center", gap: 7, minHeight: 44, padding: 0, cursor: "pointer", fontFamily: bodyFont, fontSize: 17, fontWeight: 500, whiteSpace: "nowrap", borderBottom: mega === index ? `2px solid ${accent}` : "2px solid transparent" }}>
                  {item.star && <StarIcon />}<span>{item.label}</span><ChevronDown open={mega === index} />
                </button>
              ) : (
                <a key={item.label} href={item.href || "#"} style={{ minHeight: 44, display: "inline-flex", alignItems: "center", color: fg, textDecoration: "none", fontSize: 17, fontWeight: 500, whiteSpace: "nowrap" }}>{item.label}</a>
              ))}
            </nav>
          )}
        </div>
        {desktop ? (
          <div style={{ display: "flex", alignItems: "center", gap: 28, flexShrink: 0 }}>
            <a href="#" style={{ textDecoration: "none", color: fg, fontSize: 17, fontWeight: 500, whiteSpace: "nowrap" }}>{secondary}</a>
            <PrimaryButton />
          </div>
        ) : (
          <div style={{ display: "flex", alignItems: "center", gap: 14, flexShrink: 0 }}>
            {tablet && <PrimaryButton />}
            <button type="button" aria-label={drawerOpen ? "Close menu" : "Open menu"} aria-expanded={drawerOpen} onClick={() => setDrawerOpen((v) => !v)}
              style={{ ...iconBtn, width: 46, height: 46, borderRadius: 12, border: `1px solid ${border}`, background: surface }}>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none">{drawerOpen ? <path d="M6 6l12 12M18 6L6 18" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /> : <path d="M4 7h16M4 12h16M4 17h16" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />}</svg>
            </button>
          </div>
        )}
      </div>
      <MegaMenu />
      <Drawer />
    </header>
  );
}

// Layered Depth Hero — 4 background shape layers translate at different speeds
// behind a sharp foreground headline. Element-scoped scroll so it works inside
// preview frames. Props: { content, theme }. Neutral placeholder media only.
import { useRef, useState, useEffect } from "react";
import { motion, useScroll, useTransform, useSpring, useReducedMotion } from "framer-motion";

export default function Section({ content, theme }) {
  const c = content || {};
  const eyebrow = c.eyebrow || "Design system";
  const title = c.title || "Depth that draws the eye down the page";
  const description = c.description || "Layered shapes drift at their own pace as visitors scroll, giving a flat hero a real sense of space without stealing focus from your message.";
  const primary = c.primaryButtonLabel || "Get started";
  const secondary = c.secondaryButtonLabel || "See how it works";

  const rootRef = useRef(null);
  const [w, setW] = useState(1280);
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const ro = new ResizeObserver((entries) => {
      const box = entries[0]?.borderBoxSize?.[0]?.inlineSize;
      setW(box || el.clientWidth);
    });
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const narrow = w < 700, mid = w >= 700 && w < 1024;
