  return (
    <motion.div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 12, opacity: reduce ? (index === 0 ? 1 : 0) : op, y: reduce ? 0 : yy, color: theme.mutedTextColor }}>
