// Mouse + Scroll Tilt Layers — depth layers respond to both pointer position
// (subtle 3D tilt) and scroll (vertical drift). Props: { content, theme }.
import { useRef, useState, useEffect } from "react";
import { motion, useScroll, useTransform, useSpring, useMotionValue, useReducedMotion } from "framer-motion";

export default function Section({ content, theme }) {
  const c = content || {};
  const eyebrow = c.eyebrow || "Interactive";
  const title = c.title || "Depth that follows the cursor";
  const description = c.description || "Move your pointer and the layers tilt in space; scroll and they drift apart. Subtle 3D that rewards attention without getting in the way.";
  const primary = c.primaryButtonLabel || "Try the demo";

  const rootRef = useRef(null);
  const [w, setW] = useState(1280);
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const ro = new ResizeObserver((e) => setW(e[0]?.borderBoxSize?.[0]?.inlineSize || el.clientWidth));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const narrow = w < 700, mid = w >= 700 && w < 1024;
  const padX = narrow ? 20 : mid ? 40 : 60;
  const padY = narrow ? 72 : mid ? 88 : 112;
  const reduce = useReducedMotion();

  // Pointer → tilt
  const mx = useMotionValue(0), my = useMotionValue(0);
  const rotX = useSpring(useTransform(my, [-0.5, 0.5], [8, -8]), { stiffness: 120, damping: 18 });
  const rotY = useSpring(useTransform(mx, [-0.5, 0.5], [-10, 10]), { stiffness: 120, damping: 18 });
  const onMove = (e) => {
    const r = e.currentTarget.getBoundingClientRect();
    mx.set((e.clientX - r.left) / r.width - 0.5);
    my.set((e.clientY - r.top) / r.height - 0.5);
  };
  const onLeave = () => { mx.set(0); my.set(0); };

  // Scroll → drift apart
  const { scrollYProgress } = useScroll({ target: rootRef, offset: ["start end", "end start"] });
  const yBack = useSpring(useTransform(scrollYProgress, [0, 1], [-30, 50]), { stiffness: 60, damping: 22 });
  const yFront = useSpring(useTransform(scrollYProgress, [0, 1], [40, -60]), { stiffness: 60, damping: 22 });

  const tint = (a) => theme.accentColor + a;
  const layerTransform = reduce ? {} : { rotateX: rotX, rotateY: rotY };

  return (
    <section ref={rootRef} onMouseMove={reduce ? undefined : onMove} onMouseLeave={onLeave} style={{ overflow: "hidden", background: theme.backgroundColor, color: theme.textColor, fontFamily: theme.bodyFont, padding: `${padY}px ${padX}px` }}>
      <div style={{ maxWidth: 1120, margin: "0 auto", display: narrow ? "block" : "grid", gridTemplateColumns: "1fr 1fr", gap: 48, alignItems: "center" }}>
        {/* Copy */}
        <div>
          <span style={{ fontSize: 13, fontWeight: 700, letterSpacing: "0.12em", textTransform: "uppercase", color: theme.accentColor }}>{eyebrow}</span>
          <h2 style={{ fontFamily: theme.headingFont, fontWeight: 800, letterSpacing: "-0.02em", lineHeight: 1.08, margin: "14px 0 0", fontSize: narrow ? 30 : 46 }}>{title}</h2>
          <p style={{ margin: "18px 0 0", fontSize: narrow ? 16 : 18, lineHeight: 1.65, color: theme.mutedTextColor }}>{description}</p>
          <a href="#" style={{ display: "inline-block", marginTop: 26, background: theme.buttonBgColor, color: theme.buttonTextColor, fontWeight: 600, fontSize: 15, padding: "12px 22px", borderRadius: theme.radius, textDecoration: "none", boxShadow: theme.shadow }}>{primary}</a>
        </div>

