            <motion.div style={{ position: "absolute", inset: "22%", borderRadius: theme.radius, border: "2px solid " + tint("55"), transform: "translateZ(10px)" }} />
            <motion.div style={{ position: "absolute", inset: "30%", borderRadius: theme.radius, background: theme.surfaceColor, border: "1px solid " + theme.borderColor, boxShadow: theme.shadow, transform: "translateZ(60px)", display: "grid", placeItems: "center", color: theme.mutedTextColor, y: reduce ? 0 : yFront }}>
              <svg width="40" height="40" viewBox="0 0 24 24" fill="none"><rect x="3" y="4" width="18" height="16" rx="2" stroke="currentColor" strokeWidth="1.6" /><circle cx="8.5" cy="9.5" r="1.8" stroke="currentColor" strokeWidth="1.6" /><path d="m4 17 4.5-4 3.5 3 3-2.5L20 17" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" /></svg>
