  // Measure the media box so the parallax travel scales to each image's height
  // — pronounced movement that never exceeds the over-scan (no gaps).
  const boxRef = useRef(null);
  const [boxH, setBoxH] = useState(0);
  useEffect(() => {
    const el = boxRef.current;
    if (!el) return;
    const ro = new ResizeObserver((e) => setBoxH(e[0]?.borderBoxSize?.[0]?.blockSize || el.clientHeight));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

  const { scrollYProgress } = useScroll({ target: ref, offset: ["start end", "end start"] });
  // Travel = 18% of the media height each way; inner is over-scanned by 24%.
  const travel = boxH ? boxH * 0.18 : 60;
  const yRaw = useTransform(scrollYProgress, [0, 1], [travel, -travel]);
  const mediaY = useSpring(yRaw, { stiffness: 70, damping: 26, mass: 0.4 });

  const width = narrow ? "100%" : spec.w;
  const align = narrow ? "stretch" : spec.align;

  return (
    <figure ref={ref} style={{ margin: 0, width, alignSelf: align }}>
      <div ref={boxRef} style={{ position: "relative", overflow: "hidden", borderRadius: theme.radius, border: "1px solid " + theme.borderColor, background: theme.surfaceColor }}>
