          initial={reduce ? { opacity: 0 } : { clipPath: "inset(100% 0 0 0)", scale: 1.06, opacity: 0 }}
          animate={inView ? { clipPath: "inset(0% 0 0 0)", scale: 1, opacity: 1 } : {}}
          transition={{ duration: 0.9, ease: EASE }}
          style={{ aspectRatio: narrow ? "4 / 3" : spec.ratio }}
