    { title: "Harbor Offices", text: "Commercial" },
    { title: "Ridge Cabin", text: "Residential" },
  ]);

  const rootRef = useRef(null);
  const [w, setW] = useState(1280);
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const ro = new ResizeObserver((e) => setW(e[0]?.borderBoxSize?.[0]?.inlineSize || el.clientWidth));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const narrow = w < 700, mid = w >= 700 && w < 1024;
  const padX = narrow ? 20 : mid ? 40 : 60;
  const padY = narrow ? 64 : mid ? 88 : 120;
  const reduce = useReducedMotion();

  const nCols = narrow ? 1 : mid ? 2 : 3;
  const cols = Array.from({ length: nCols }, () => []);
  items.forEach((it, i) => cols[i % nCols].push(it));

  // Whole-column parallax speeds (px each way). Middle column travels most.
  const speeds = [-40, -90, -20];
  const { scrollYProgress } = useScroll({ target: rootRef, offset: ["start end", "end start"] });

  const ratios = ["4 / 5", "1 / 1", "4 / 3", "3 / 4"];

  return (
    <section ref={rootRef} style={{ overflow: "hidden", background: theme.backgroundColor, color: theme.textColor, fontFamily: theme.bodyFont, padding: `${padY}px ${padX}px` }}>
      <div style={{ maxWidth: 1280, margin: "0 auto" }}>
