        <div style={{ display: "flex", gap: narrow ? 40 : "4%", alignItems: "flex-start" }}>
          {cols.map((col, ci) => (
            <ParallaxColumn
              key={ci}
              col={col}
              colIndex={ci}
              nCols={nCols}
              speed={speeds[ci % speeds.length]}
              progress={scrollYProgress}
              reduce={reduce}
              narrow={narrow}
              ratios={ratios}
              theme={theme}
