function ParallaxColumn({ col, colIndex, nCols, speed, progress, reduce, narrow, ratios, theme }) {
  const yRaw = useTransform(progress, [0, 1], [-speed, speed]);
  const y = useSpring(yRaw, { stiffness: 60, damping: 24, mass: 0.5 });
  // Middle column drops a little for a masonry offset.
  const offset = narrow ? 0 : colIndex === 1 ? 64 : colIndex === 2 ? 28 : 0;

  return (
    <motion.div
      style={{ flex: 1, minWidth: 0, marginTop: offset, display: "flex", flexDirection: "column", gap: narrow ? 40 : 40, y: reduce ? 0 : y }}
    >
      {col.map((it, i) => (
        <Tile key={i} it={it} ratio={ratios[(colIndex + i) % ratios.length]} theme={theme} reduce={reduce} />
      ))}
    </motion.div>
  );
}

function Tile({ it, ratio, theme, reduce }) {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, amount: 0.25 });
  const EASE = [0.22, 1, 0.36, 1];
  return (
    <figure ref={ref} style={{ margin: 0 }}>
