  const staticCard = reduce;
  const ratio = narrow ? "3 / 4" : mid ? "3 / 2" : "16 / 8"; // same as Full-Bleed Chapter Scroll

  return (
    <div style={{ position: "sticky", top: narrow ? 64 : 84, marginBottom: isLast ? 0 : gap }}>
      <motion.div
