      <p style={{ margin: 0, fontFamily: bodyFont, fontSize: 15, lineHeight: 1.6, color: text }}>{it.text}</p>
      <div style={{ marginTop: 20, display: "flex", alignItems: "center", gap: 12 }}>
        <span
          aria-hidden="true"
          style={{
            display: "grid",
            placeItems: "center",
            width: 40,
            height: 40,
            borderRadius: 999,
            flexShrink: 0,
            background: accent + "1f",
            color: accent,
            fontFamily: headingFont,
            fontWeight: 700,
            fontSize: 14,
          }}
        >
          {initials(it.title)}
        </span>
        <span style={{ display: "flex", flexDirection: "column" }}>
          <span style={{ fontFamily: headingFont, fontWeight: 500, lineHeight: 1.25, color: text }}>{it.title}</span>
          {it.icon ? <span style={{ fontFamily: bodyFont, fontSize: 13, lineHeight: 1.3, color: muted }}>{it.icon}</span> : null}
        </span>
      </div>
    </div>
  );

  const Column = ({ list, duration }) => (
    <div style={{ flex: 1, minWidth: 0 }}>
      <motion.div
        animate={reduce ? undefined : { translateY: "-50%" }}
        transition={{ duration, repeat: Infinity, ease: "linear", repeatType: "loop" }}
        style={{ display: "flex", flexDirection: "column", gap: 24, paddingBottom: 24 }}
      >
        {[0, 1].map((dup) => (
          <div key={dup} style={{ display: "flex", flexDirection: "column", gap: 24 }}>
            {list.map((it, i) => (
              <Card it={it} key={i} />
            ))}
          </div>
        ))}
      </motion.div>
    </div>
  );

  return (
    <section
      ref={rootRef}
      style={{ background: bg, padding: padY + "px " + padX + "px", fontFamily: bodyFont }}
    >
      <div style={{ maxWidth: 1240, margin: "0 auto" }}>
        <div style={{ maxWidth: 600, margin: "0 auto", textAlign: "center", display: "flex", flexDirection: "column", alignItems: "center" }}>
          {eyebrow ? (
            <p style={{ margin: "0 0 12px", fontSize: 12, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: accent }}>
              {eyebrow}
            </p>
          ) : null}
          <h2 style={{ margin: 0, fontFamily: headingFont, fontWeight: 700, letterSpacing: "-0.02em", lineHeight: 1.05, fontSize: mobile ? 32 : tablet ? 42 : 51, color: text }}>
            {title}
          </h2>
          {description ? (
            <p style={{ margin: "16px 0 0", fontSize: 18, lineHeight: 1.6, color: muted }}>{description}</p>
          ) : null}
        </div>

        <div
          style={{
            marginTop: 48,
            display: "flex",
            justifyContent: "center",
            gap: 24,
            maxHeight: 740,
            overflow: "hidden",
            WebkitMaskImage: "linear-gradient(to bottom, transparent, black 20%, black 80%, transparent)",
            maskImage: "linear-gradient(to bottom, transparent, black 20%, black 80%, transparent)",
          }}
        >
          {columns.map((list, i) => (
            <Column list={list} duration={durations[i % durations.length]} key={i} />
          ))}
        </div>
      </div>
    </section>
  );
}

