// Trending Carousel — editorial product rail bound to the live catalog
// (title=name, text=price line, icon=badge, image, href). Desktop = snap-scroll
// rail aligned to the content container with prev/next; mobile = 2-column grid.
export default function Section({ content = {}, theme = {} }) {
  const t = {
    bg: theme.backgroundColor || "#ffffff",
    surface: theme.surfaceColor || "#f4f1ee",
    text: theme.textColor || "#111827",
    muted: theme.mutedTextColor || "#6b7280",
    border: theme.borderColor || "#e5e7eb",
    accent: theme.accentColor || "#E94B6F",
    btnBg: theme.buttonBgColor || "#111827",
    btnText: theme.buttonTextColor || "#ffffff",
    radius: theme.radius || "10px",
    heading: theme.headingFont || "Inter, system-ui, sans-serif",
    body: theme.bodyFont || "Inter, system-ui, sans-serif",
  };
  const reduce = useReducedMotion();
  const items =
    Array.isArray(content.items) && content.items.length
      ? content.items
      : Array.from({ length: 6 }).map((_, i) => ({ title: "Product " + (i + 1), text: "$0.00", icon: i === 1 ? "Save 10%" : "", image: "" }));

  const rail = useRef(null);
  // Shared Section Runtime: container width + standard breakpoint (no local
  // observers — see SECTION_RUNTIME_RULES.md).
  const { width, breakpoint } = useSectionRuntime();
  const w = width || 360; // mobile-first fallback before the first measurement

  const mobile = isCompactBreakpoint(breakpoint);
  const per = w < 900 ? 2.3 : w < 1200 ? 3.3 : 4.2;
  const gap = 24;
  const cardW = Math.floor((w - gap * (Math.ceil(per) - 1)) / per);
  const scrollBy = (dir) => { if (rail.current) rail.current.scrollBy({ left: dir * (cardW + gap) * 2, behavior: "smooth" }); };

  const Card = (p, i) => (
    <motion.a
      key={i}
      href={p.href || undefined}
      initial={reduce ? false : { opacity: 0, y: 18 }}
      whileInView={reduce ? undefined : { opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-60px" }}
      transition={{ duration: 0.5, delay: Math.min(i * 0.05, 0.3), ease: [0.22, 1, 0.36, 1] }}
      style={{ flex: mobile ? undefined : "0 0 auto", width: mobile ? undefined : cardW, scrollSnapAlign: "start", textDecoration: "none", color: "inherit" }}
    >
      <div style={{ position: "relative", aspectRatio: "4 / 5", background: t.surface, borderRadius: t.radius, overflow: "hidden" }}>
        {p.image
          ? <img src={p.image} alt={p.title || ""} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
          : <div style={{ width: "100%", height: "100%", display: "grid", placeItems: "center", color: t.muted }}>
              <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.3"><rect x="3" y="3" width="18" height="18" rx="2" /><circle cx="8.5" cy="8.5" r="1.5" /><path d="m21 15-5-5L5 21" /></svg>
            </div>}
        {p.icon ? <span style={{ position: "absolute", top: 12, left: 12, background: t.accent, color: "#fff", fontSize: 10.5, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", padding: "5px 9px", borderRadius: 6 }}>{p.icon}</span> : null}
        <span style={{ position: "absolute", bottom: 12, right: 12, height: 40, width: 40, borderRadius: 10, background: t.bg, color: t.text, display: "grid", placeItems: "center", boxShadow: "0 4px 12px rgba(0,0,0,0.14)" }}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round"><path d="M5 8h14l-1 12H6L5 8Z" /><path d="M9 8a3 3 0 0 1 6 0" /></svg>
        </span>
      </div>
      <p style={{ margin: mobile ? "10px 0 0" : "14px 0 0", fontFamily: t.heading, fontSize: mobile ? 14.5 : 15.5, fontWeight: 700, whiteSpace: mobile ? "nowrap" : undefined, overflow: mobile ? "hidden" : undefined, textOverflow: mobile ? "ellipsis" : undefined }}>{p.title}</p>
      {p.text ? <p style={{ margin: "3px 0 0", fontSize: mobile ? 13 : 14, color: t.muted }}>{p.text}</p> : null}
    </motion.a>
  );

  return (
    <section style={{ background: t.bg, color: t.text, fontFamily: t.body, padding: "80px 0" }}>
      <div style={{ maxWidth: 1280, margin: "0 auto", padding: mobile ? "0 24px" : "0 40px" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 16, flexWrap: "wrap" }}>
          <div>
            {content.eyebrow ? <p style={{ margin: 0, textTransform: "uppercase", letterSpacing: "0.18em", fontSize: 12, fontWeight: 600, color: t.muted }}>{content.eyebrow}</p> : null}
            <h2 style={{ margin: content.eyebrow ? "8px 0 0" : 0, fontFamily: t.heading, fontWeight: 800, letterSpacing: "-0.02em", fontSize: mobile ? 26 : breakpoint === "tablet" ? 40 : 50, lineHeight: mobile ? 1.1 : 1 }}>{content.title || "Trending this Season"}</h2>
          </div>
          {content.primaryButtonLabel ? (
            <a href={content.primaryButtonHref || "#"} style={{ whiteSpace: "nowrap", background: t.btnBg, color: t.btnText, padding: "13px 24px", borderRadius: t.radius, fontSize: 12, fontWeight: 700, letterSpacing: "0.1em", textTransform: "uppercase", textDecoration: "none" }}>{content.primaryButtonLabel}</a>
          ) : null}
        </div>

        {mobile ? (
          <div style={{ marginTop: 28, display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
            {items.map(Card)}
          </div>
        ) : (
          <div style={{ position: "relative", marginTop: 32 }}>
            <div ref={rail} style={{ display: "flex", gap, overflowX: "auto", scrollSnapType: "x mandatory", paddingBottom: 8, scrollbarWidth: "none" }}>
              {items.map(Card)}
            </div>
            <button type="button" aria-label="Previous" onClick={() => scrollBy(-1)} style={navBtn(t, "left")}>{arrow("left")}</button>
            <button type="button" aria-label="Next" onClick={() => scrollBy(1)} style={navBtn(t, "right")}>{arrow("right")}</button>
          </div>
        )}
      </div>
    </section>
  );
}

function navBtn(t, side) {
  return {
    position: "absolute", top: "40%", [side]: -18, transform: "translateY(-50%)",
    height: 44, width: 44, borderRadius: 999, border: "1px solid " + t.border,
    background: t.bg, color: t.text, cursor: "pointer", display: "grid", placeItems: "center",
    boxShadow: "0 6px 18px rgba(0,0,0,0.12)", zIndex: 2,
  };
}
function arrow(dir) {
  const d = dir === "left" ? "M15 6l-6 6 6 6" : "M9 6l6 6-6 6";
  return <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d={d} /></svg>;
}

