      <aside style={{ position: "fixed", top: 0, right: 0, height: "100%", width: cartW, background: t.bg, color: t.text, boxShadow: "-16px 0 40px rgba(0,0,0,0.18)", transform: cart ? "translateX(0)" : "translateX(100%)", transition: "transform .3s cubic-bezier(.22,1,.36,1)", zIndex: 80, display: "flex", flexDirection: "column" }}>
