  const { width, breakpoint } = useSectionRuntime();
  const w = width || 390; // mobile-first fallback before the first measurement
  const mobile = isCompactBreakpoint(breakpoint);
  const tablet = breakpoint === "tablet";
  // Column layout driven by the standard container breakpoint.
  const mainCols = mobile ? "1fr" : tablet ? "1fr 1fr" : "1.4fr 0.8fr 0.8fr 1.6fr";
