  const half = Math.ceil(items.length / 2);
  const cols = [{ head: "Help", links: items.slice(0, half) }, { head: "Company", links: items.slice(half) }];
  const white = (o) => `rgba(255,255,255,${o})`;

  return (
    <footer style={{ background: "#0e0e10", color: "#fff", fontFamily: t.body }}>
