          {features.map((f, i) => (
            <div key={i} style={{ textAlign: mobile ? "left" : "center", padding: mobile ? "0" : "8px 20px", borderLeft: !mobile && i > 0 ? `1px solid ${t.border}` : "none" }}>
              <p style={{ margin: 0, fontFamily: t.heading, fontSize: 16, fontWeight: 700 }}>{f.title}</p>
              <p style={{ margin: "4px 0 0", fontSize: 13.5, color: t.muted }}>{f.text}</p>
            </div>
          ))}
        </div>
      </div>

      <div style={{ maxWidth: 1280, margin: "0 auto", padding: mobile ? "36px 24px 24px" : "56px 24px 24px" }}>
        <div style={{ display: "grid", gridTemplateColumns: mainCols, gap: mobile ? 4 : 32, alignItems: "start" }}>
          <p style={{ margin: mobile ? "0 0 12px" : 0, fontSize: 14, lineHeight: 1.6, color: white(0.7), maxWidth: 260 }}>{content.description || "Considered essentials, made to last — and to move with you."}</p>

          {cols.map((c) => (
            <div key={c.head} style={mobile ? { borderTop: `1px solid ${white(0.12)}` } : undefined}>
              {mobile ? (
                <button type="button" onClick={() => setOpenCol(openCol === c.head ? null : c.head)}
