                </button>
              ) : <p style={{ margin: 0, fontSize: 12.5, fontWeight: 700 }}>{c.head}</p>}
              {(!mobile || openCol === c.head) && (
                <div style={{ paddingBottom: mobile ? 16 : 0 }}>
                  {c.links.map((l, i) => <a key={i} href={l.href || "#"} style={{ display: "block", marginTop: mobile ? 12 : 14, fontSize: 14, color: white(0.7), textDecoration: "none" }}>{l.title}</a>)}
                </div>
