              <button type="button" aria-label="Subscribe" style={{ height: 36, width: 36, borderRadius: 8, background: t.accent, color: "#fff", border: "none", cursor: "pointer", display: "grid", placeItems: "center" }}><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14M13 6l6 6-6 6" /></svg></button>
            </div>
          </div>
        </div>

        <div style={{ marginTop: 40, fontFamily: t.heading, fontWeight: 800, letterSpacing: "0.02em", textTransform: "uppercase", fontSize: markSize, lineHeight: 0.9, color: "transparent", WebkitTextStroke: `1px ${white(0.35)}`, whiteSpace: "nowrap", overflow: "hidden" }}>{brand}</div>

        <div style={{ marginTop: 24, display: "flex", flexWrap: "wrap", alignItems: "center", justifyContent: "space-between", gap: 16, borderTop: `1px solid ${white(0.12)}`, paddingTop: 20, fontSize: 12.5, color: white(0.6) }}>
          <div style={{ display: "flex", gap: 14 }}>
            {[0, 1, 2].map((s) => <span key={s} style={{ height: 30, width: 30, borderRadius: 999, background: white(0.12), display: "grid", placeItems: "center", color: "#fff" }}><svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6"><rect x="3" y="3" width="18" height="18" rx="5" /><circle cx="12" cy="12" r="4" /></svg></span>)}
          </div>
          <span>© {new Date().getFullYear()} {brand}. All rights reserved.</span>
        </div>
      </div>
    </footer>
  );
}

import { useRef } from "react";
import { motion, useReducedMotion } from "framer-motion";
import { useSectionRuntime, isCompactBreakpoint } from "section-runtime";

// Testimonial Project Carousel — wide horizontal cards (portrait + big quote +
// author + "View project" link + a headline stat), with prev/next controls and
// snap scrolling. Responsive via the shared Section Runtime (container width,
// never the viewport). Placeholder media + original copy only.
// content: eyebrow, title, items[] { text (quote), title (name), role, stat,
//          statLabel, href, image }.
export default function Section({ content = {}, theme = {} }) {
  const t = {
    bg: theme.backgroundColor || "#f2f1ef",
    card: theme.surfaceColor || "#faf9f8",
    media: theme.borderColor || "#e6e2dd",
    text: theme.textColor || "#141414",
    muted: theme.mutedTextColor || "#6b7280",
    border: theme.borderColor || "#e6e2dd",
    accent: theme.accentColor || "#f4682b",
    radius: theme.radius || "20px",
    heading: theme.headingFont || "Inter, system-ui, sans-serif",
    body: theme.bodyFont || "Inter, system-ui, sans-serif",
  };

  const { width, breakpoint } = useSectionRuntime();
  const w = width || 390;
  const mobile = isCompactBreakpoint(breakpoint);
  const reduce = useReducedMotion();

  const padX = w < 700 ? 20 : w < 1024 ? 32 : 48;
  const gap = mobile ? 16 : 24;
  // One primary card; on larger widths it leaves room so neighbours peek in.
  const cardW = mobile ? w - padX * 2 : Math.min(Math.round(w * 0.9), 1180);

  const rail = useRef(null);
  const nudge = (dir) => {
    if (rail.current) rail.current.scrollBy({ left: dir * (cardW + gap), behavior: reduce ? "auto" : "smooth" });
  };

  const items = (Array.isArray(content.items) && content.items.length ? content.items : DEFAULTS);

  const arrow = (dir) => (
    <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      {dir === "left" ? <path d="M15 6l-6 6 6 6" /> : <path d="M9 6l6 6-6 6" />}
    </svg>
  );
  const navBtn = {
    height: 44, width: 44, borderRadius: 999, display: "grid", placeItems: "center",
    background: t.card, color: t.text, border: `1px solid ${t.border}`, cursor: "pointer",
  };

  return (
    <section style={{ background: t.bg, color: t.text, fontFamily: t.body, padding: `${mobile ? 56 : 88}px 0` }}>
      {/* Header row — optional eyebrow/title + prev/next controls */}
      <div style={{ maxWidth: 1400, margin: "0 auto", padding: `0 ${padX}px`, display: "flex", alignItems: "flex-end", justifyContent: "space-between", gap: 16, marginBottom: mobile ? 22 : 30 }}>
        <div style={{ minWidth: 0 }}>
          {content.eyebrow ? <p style={{ margin: 0, fontSize: 12.5, fontWeight: 700, letterSpacing: "0.14em", textTransform: "uppercase", color: t.accent }}>{content.eyebrow}</p> : null}
          {content.title ? <h2 style={{ margin: content.eyebrow ? "10px 0 0" : 0, fontFamily: t.heading, fontWeight: 800, letterSpacing: "-0.02em", lineHeight: 1.05, fontSize: mobile ? 26 : 38, maxWidth: 560 }}>{content.title}</h2> : null}
        </div>
        <div style={{ display: "flex", gap: 10, flex: "0 0 auto" }}>
          <button type="button" aria-label="Previous" onClick={() => nudge(-1)} style={navBtn}>{arrow("left")}</button>
          <button type="button" aria-label="Next" onClick={() => nudge(1)} style={navBtn}>{arrow("right")}</button>
        </div>
      </div>

      {/* Snap-scrolling rail */}
      <div
        ref={rail}
        style={{
          display: "flex", gap, overflowX: "auto", scrollSnapType: "x mandatory",
          padding: `4px ${padX}px 8px`, scrollbarWidth: "none", WebkitOverflowScrolling: "touch",
        }}
      >
        {items.map((it, i) => (
          <motion.article
            key={i}
            initial={reduce ? false : { opacity: 0, y: 18 }}
            whileInView={reduce ? undefined : { opacity: 1, y: 0 }}
            viewport={{ once: true, margin: "-10%" }}
            transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
            style={{
              flex: `0 0 ${cardW}px`, width: cardW, scrollSnapAlign: "center",
              background: t.card, border: `1px solid ${t.border}`, borderRadius: t.radius, overflow: "hidden",
              display: "grid",
              gridTemplateColumns: mobile ? "1fr" : "minmax(220px, 38%) 1fr",
            }}
          >
            {/* Portrait / media */}
            <div style={{ position: "relative", background: t.media, aspectRatio: mobile ? "16 / 10" : undefined, minHeight: mobile ? undefined : 380 }}>
              {it.image
                ? <img src={it.image} alt={it.title || ""} style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover" }} />
                : (
                  <div style={{ position: "absolute", inset: 0, display: "grid", placeItems: "center", color: t.muted }}>
                    <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.3"><circle cx="12" cy="9" r="3.2" /><path d="M5 20a7 7 0 0 1 14 0" /></svg>
                  </div>
                )}
            </div>

            {/* Quote + author + stat */}
            <div style={{ display: "flex", flexDirection: "column", padding: mobile ? "22px 22px 24px" : "32px 34px 30px", gap: 14 }}>
              <div style={{ display: "flex", justifyContent: "flex-end" }}>
                <a href={it.href || "#"} style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 14, fontWeight: 500, color: t.text, textDecoration: "none" }}>
                  View project
                  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round"><path d="M7 17 17 7M8 7h9v9" /></svg>
                </a>
              </div>

              <p style={{ margin: 0, flex: 1, fontFamily: t.heading, fontWeight: 500, letterSpacing: "-0.01em", lineHeight: 1.28, fontSize: mobile ? 20 : w < 1180 ? 24 : 29, color: t.text }}>
                {it.text || DEFAULTS[0].text}
              </p>

              <div style={{ display: "flex", alignItems: "flex-end", justifyContent: "space-between", gap: 16, flexWrap: "wrap", marginTop: 6 }}>
                <div style={{ minWidth: 0 }}>
                  <p style={{ margin: 0, fontSize: 16, fontWeight: 600 }}>{it.title || "Client name"}</p>
                  {it.role ? <p style={{ margin: "3px 0 0", fontSize: 13.5, color: t.muted }}>{it.role}</p> : null}
                </div>
                {it.stat ? (
                  <div style={{ textAlign: "right" }}>
                    <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "flex-end", gap: 4 }}>
                      <span style={{ fontFamily: t.heading, fontWeight: 700, letterSpacing: "-0.03em", lineHeight: 1, fontSize: mobile ? 40 : 52 }}>{it.stat}</span>
                      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={t.accent} strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round" style={{ marginTop: 4 }}><path d="M12 19V5M6 11l6-6 6 6" /></svg>
                    </div>
                    {it.statLabel ? <p style={{ margin: "6px 0 0", fontSize: 13.5, color: t.muted }}>{it.statLabel}</p> : null}
                  </div>
                ) : null}
              </div>
            </div>
          </motion.article>
        ))}
      </div>
    </section>
  );
}

