import { useEffect, useMemo, useRef, useState } from "react";
import { useSectionRuntime } from "section-runtime";

// Sticky Stack Scroll — the heading AND the cards live in ONE sticky "stage"
// that pins together; the cards stack (rise + cover) as you scroll, and when
// the last one lands the whole block (heading + cards) unpins and scrolls away
// together. Scroll progress is measured from the section's OWN scroll
// container (window on a live page, the device-frame's scroller in previews),
// so the effect is identical on desktop, tablet and mobile. Placeholder media +
// original copy only.
// content: title, items[] { title, description(or text), meta, linkLabel,
//          href, background, visualLabel }.
export default function Section({ content = {}, theme = {}, siteHeaderHeight = 64 }) {
  const rootRef = useRef(null);
  const { width, breakpoint } = useSectionRuntime();
  const w = width || 1200;
  const mobile = breakpoint === "mobile" || breakpoint === "largeMobile";
  const [reduce, setReduce] = useState(false);
  useEffect(() => {
    const m = window.matchMedia("(prefers-reduced-motion: reduce)");
    setReduce(m.matches);
    const on = () => setReduce(m.matches);
    m.addEventListener?.("change", on);
    return () => m.removeEventListener?.("change", on);
  }, []);
  const pinned = !reduce;

  const items = Array.isArray(content.items) && content.items.length ? content.items : DEFAULT_ITEMS;
  const n = items.length;

  const t = useMemo(
    () => ({
      background: theme.backgroundColor || "#FFFFFF",
      surface: theme.surfaceColor || "#F6F7F9",
      text: theme.textColor || "#111827",
      muted: theme.mutedTextColor || "#6B7280",
      accent: theme.accentColor || "#2563EB",
      border: theme.borderColor || "#E5E7EB",
      radius: theme.radius || "24px",
      heading: theme.headingFont || "Inter, system-ui, sans-serif",
      body: theme.bodyFont || "Inter, system-ui, sans-serif",
      shadow: theme.shadow || "0 18px 50px rgba(17,24,39,0.12)",
    }),
    [theme],
  );

  const padX = mobile ? 20 : breakpoint === "tablet" ? 28 : 48;
  const cardH = mobile
    ? Math.round(Math.min(Math.max(w * 1.42, 490), 600))
    : breakpoint === "tablet"
      ? Math.round(Math.min(Math.max(w * 0.62, 470), 600))
      : Math.round(Math.min(Math.max(w * 0.42, 500), 640));
  const stepPx = mobile ? 240 : breakpoint === "tablet" ? 300 : 340;

  // Full-viewport section: the stage fills the screen (measured from the actual
  // scroll container) with the content centered on load. sectionH adds the
  // scroll room for the cards to stack.
  const [vh, setVh] = useState(760);
  const stageH = Math.max(vh - siteHeaderHeight, cardH + 180);
  const sectionH = vh + n * stepPx;

  // Scroll progress (0..1) across the section, measured against the nearest
  // scrollable ancestor (window OR a nested preview scroller) — never assumes
  // the window, so it animates inside the device-frame previews too.
  const [progress, setProgress] = useState(0);
  useEffect(() => {
    if (!pinned) return;
    const el = rootRef.current;
    if (!el) return;
    let scroller = el.parentElement;
    while (scroller && scroller !== document.body) {
      const oy = getComputedStyle(scroller).overflowY;
      if ((oy === "auto" || oy === "scroll") && scroller.scrollHeight > scroller.clientHeight + 4) break;
      scroller = scroller.parentElement;
    }
    const useWindow = !scroller || scroller === document.body || scroller === document.documentElement;
    const target = useWindow ? window : scroller;
    let raf = 0;
    const measure = () => {
      raf = 0;
      const cvH = useWindow ? window.innerHeight : scroller.clientHeight;
      setVh((prev) => (Math.abs(prev - cvH) > 2 ? cvH : prev));
      const rect = el.getBoundingClientRect();
      const cvTop = useWindow ? 0 : scroller.getBoundingClientRect().top;
      const denom = rect.height - cvH;
      const p = denom > 0 ? Math.min(1, Math.max(0, (cvTop - rect.top) / denom)) : 0;
      setProgress(p);
    };
    const onScroll = () => { if (!raf) raf = requestAnimationFrame(measure); };
    measure();
    target.addEventListener("scroll", onScroll, { passive: true });
    window.addEventListener("resize", onScroll);
    return () => { if (raf) cancelAnimationFrame(raf); target.removeEventListener("scroll", onScroll); window.removeEventListener("resize", onScroll); };
  }, [pinned, breakpoint]);

  const span = 0.86; // cards finish stacking by 0.86, brief hold, then release
  const seg = span / Math.max(n - 1, 1);

  const cardStyle = (i) => {
    if (!pinned) return { position: "relative", width: "100%" };
    const enterStart = Math.max((i - 1) * seg, 0);
    const tEnter = i === 0 ? 1 : clamp((progress - enterStart) / seg, 0, 1);
    const y = (1 - tEnter) * 130; // rise from 130% (below, clipped) to 0
    const isLast = i === n - 1;
    const coverStart = i * seg + seg * 0.5;
    const tCover = isLast ? 0 : clamp((progress - coverStart) / (seg * 0.5), 0, 1);
    const scale = 1 - tCover * 0.06;
    return {
      position: "absolute", top: 0, left: 0, right: 0, height: cardH,
      transform: `translateY(${y}%) scale(${scale})`, transformOrigin: "center top",
      zIndex: i + 1, willChange: "transform",
    };
  };
  const dimOpacity = (i) => {
    if (!pinned || i === n - 1) return 0;
    const coverStart = i * seg + seg * 0.5;
    return clamp((progress - coverStart) / (seg * 0.5), 0, 1) * 0.4;
  };

  const cards = items.map((item, i) => (
    <article key={i} className="ff-stack__chapter" style={pinned ? undefined : { position: "relative" }}>
      <div className="ff-stack__card" style={{ background: item.background || t.surface, height: pinned ? undefined : "auto", ...cardStyle(i) }}>
        <div className="ff-stack__head">
          <h3 className="ff-stack__title">{item.title || "Chapter title"}</h3>
          <p className="ff-stack__desc">{item.description || item.text || "A short line describing this chapter and what it means for the reader."}</p>
          <a className="ff-stack__link" href={item.href || "#"}>
            <span>{item.linkLabel || "Learn more"}</span>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true"><path d="M5 12h14M13 6l6 6-6 6" /></svg>
          </a>
        </div>
        <div className="ff-stack__media" aria-hidden="true">
          <div className="ff-stack__placeholder">
            <svg width="54" height="54" viewBox="0 0 24 24" fill="none">
              <rect x="3" y="4" width="18" height="16" rx="2" stroke="currentColor" strokeWidth="1.6" />
              <circle cx="8.5" cy="9.5" r="1.8" stroke="currentColor" strokeWidth="1.6" />
              <path d="m4 17 4.5-4 3.5 3 3-2.5L20 17" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
            <span>{item.visualLabel || "Media placeholder"}</span>
          </div>
        </div>
        <div className="ff-stack__meta" aria-hidden="true">
          <span>{item.meta || "Chapter"}</span>
          <span>{String(i + 1).padStart(2, "0")} / {String(n).padStart(2, "0")}</span>
        </div>
        {pinned && i !== n - 1 && <div className="ff-stack__dim" style={{ opacity: dimOpacity(i) }} aria-hidden="true" />}
      </div>
    </article>
  ));

  return (
    <section
      ref={rootRef}
      className="ff-stack"
      data-breakpoint={breakpoint}
      style={{
        "--ff-text": t.text, "--ff-muted": t.muted, "--ff-accent": t.accent,
        "--ff-border": t.border, "--ff-radius": t.radius, "--ff-heading": t.heading,
        "--ff-body": t.body, "--ff-shadow": t.shadow, "--ff-bg": t.background,
        background: t.background, color: t.text, fontFamily: t.body,
        height: pinned ? sectionH + "px" : "auto",
        position: "relative", isolation: "isolate", width: "100%", minWidth: 0, maxWidth: "100%",
        boxSizing: "border-box", containerType: "inline-size",
      }}
    >
      <style>{CSS}</style>
      {pinned ? (
        <div className="ff-stack__stage" style={{ top: siteHeaderHeight + "px", height: stageH + "px", padding: `0 ${padX}px` }}>
          <div className="ff-stack__wrap">
            <h2 className="ff-stack__heading">{content.title || "A layered story, one chapter at a time"}</h2>
            <div className="ff-stack__zone" style={{ height: cardH + 64 }}>{cards}</div>
          </div>
        </div>
      ) : (
        <div className="ff-stack__flow" style={{ padding: `${mobile ? 40 : 48}px ${padX}px` }}>
          <h2 className="ff-stack__heading ff-stack__heading--static">{content.title || "A layered story, one chapter at a time"}</h2>
          <div className="ff-stack__flow-list">{cards}</div>
        </div>
      )}
    </section>
  );
}

function clamp(v, lo, hi) { return v < lo ? lo : v > hi ? hi : v; }

const CSS = `
  .ff-stack, .ff-stack * { box-sizing: border-box; }
  .ff-stack__stage { position: sticky; display: flex; flex-direction: column; justify-content: center; overflow: hidden; }
  .ff-stack__wrap { width: 100%; max-width: 1400px; margin-inline: auto; }
  .ff-stack__heading { margin: 0 0 16px; color: var(--ff-text); font-family: var(--ff-heading); font-size: clamp(30px, 4.2cqw, 60px); font-weight: 600; letter-spacing: -0.045em; line-height: 1.12; padding-bottom: 0.06em; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .ff-stack__zone { position: relative; width: 100%; max-width: 1400px; margin-inline: auto; overflow: hidden; }
  .ff-stack__card { width: 100%; min-width: 0; overflow: hidden; border: 1px solid var(--ff-border); border-radius: var(--ff-radius); box-shadow: var(--ff-shadow); }
  .ff-stack__head { display: grid; grid-template-columns: minmax(200px, 0.8fr) minmax(280px, 1.2fr) auto; gap: 28px; align-items: start; min-width: 0; padding: 30px 40px 18px; }
  .ff-stack__title { max-width: 12ch; margin: 0; overflow-wrap: anywhere; font-family: var(--ff-heading); font-size: clamp(26px, 2.3cqw, 38px); font-weight: 600; letter-spacing: -0.035em; line-height: 1.04; text-wrap: balance; }
  .ff-stack__desc { max-width: 620px; min-width: 0; margin: 0; color: var(--ff-text); font-size: 15px; line-height: 1.5; text-wrap: pretty; opacity: 0.86; }
  .ff-stack__link { display: inline-flex; width: fit-content; min-height: 44px; gap: 8px; align-items: center; justify-self: end; color: inherit; border-bottom: 1px solid currentColor; font-size: 15px; font-weight: 600; text-decoration: none; white-space: nowrap; }
  .ff-stack__link:focus-visible { outline: 2px solid var(--ff-accent); outline-offset: 4px; }
  .ff-stack__media { position: absolute; right: 40px; bottom: 34px; left: 40px; height: calc(100% - 150px); min-height: 0; overflow: hidden; border: 1px solid rgba(255,255,255,0.72); border-radius: 16px; background: radial-gradient(circle at 20% 20%, rgba(37,99,235,0.10), transparent 30%), linear-gradient(135deg, rgba(255,255,255,0.94), rgba(255,255,255,0.55)); display: grid; place-items: center; color: var(--ff-muted); }
  .ff-stack__placeholder { display: flex; flex-direction: column; gap: 10px; align-items: center; text-align: center; }
  .ff-stack__placeholder span { font-size: 12px; }
  .ff-stack__meta { position: absolute; right: 42px; bottom: 12px; left: 42px; display: flex; gap: 16px; justify-content: space-between; color: rgba(17,24,39,0.55); font-family: ui-monospace, SFMono-Regular, Menlo, monospace; font-size: 11px; letter-spacing: 0.08em; pointer-events: none; }
  .ff-stack__dim { position: absolute; inset: 0; background: #000; pointer-events: none; }

  .ff-stack[data-breakpoint="tablet"] .ff-stack__head { grid-template-columns: minmax(170px, 0.8fr) minmax(0, 1.2fr); grid-template-areas: "title desc" "title link"; column-gap: 18px; row-gap: 14px; align-content: start; padding: 26px 28px 18px; }
  .ff-stack[data-breakpoint="tablet"] .ff-stack__title { grid-area: title; }
  .ff-stack[data-breakpoint="tablet"] .ff-stack__desc { grid-area: desc; }
  .ff-stack[data-breakpoint="tablet"] .ff-stack__link { grid-area: link; align-self: start; justify-self: start; min-height: 0; }
  .ff-stack[data-breakpoint="tablet"] .ff-stack__media { right: 28px; bottom: 28px; left: 28px; height: calc(100% - 176px); }
  .ff-stack[data-breakpoint="tablet"] .ff-stack__meta { right: 30px; bottom: 10px; left: 30px; }

  .ff-stack[data-breakpoint="mobile"] .ff-stack__heading, .ff-stack[data-breakpoint="largeMobile"] .ff-stack__heading { white-space: normal; overflow: visible; font-size: clamp(24px, 7.4cqw, 34px); letter-spacing: -0.03em; }
  .ff-stack[data-breakpoint="mobile"] .ff-stack__card, .ff-stack[data-breakpoint="largeMobile"] .ff-stack__card { display: flex; flex-direction: column; border-radius: 18px; }
  .ff-stack[data-breakpoint="mobile"] .ff-stack__head, .ff-stack[data-breakpoint="largeMobile"] .ff-stack__head { flex: 0 0 auto; grid-template-columns: 1fr; gap: 12px; padding: 24px 20px 16px; }
  .ff-stack[data-breakpoint="mobile"] .ff-stack__title, .ff-stack[data-breakpoint="largeMobile"] .ff-stack__title { max-width: 16ch; font-size: clamp(24px, 7cqw, 32px); }
  .ff-stack[data-breakpoint="mobile"] .ff-stack__link, .ff-stack[data-breakpoint="largeMobile"] .ff-stack__link { justify-self: start; }
  .ff-stack[data-breakpoint="mobile"] .ff-stack__media, .ff-stack[data-breakpoint="largeMobile"] .ff-stack__media { position: relative; right: auto; bottom: auto; left: auto; flex: 1 1 auto; min-height: 90px; height: auto; margin: 0 18px 42px; border-radius: 14px; }
  .ff-stack[data-breakpoint="mobile"] .ff-stack__meta, .ff-stack[data-breakpoint="largeMobile"] .ff-stack__meta { right: 20px; bottom: 12px; left: 20px; }

  .ff-stack__flow-list { display: grid; gap: 20px; }
  .ff-stack__heading--static { white-space: normal; overflow: visible; }
  .ff-stack__flow-list .ff-stack__media { position: relative; right: auto; bottom: auto; left: auto; width: calc(100% - 40px); height: auto; min-height: 0; margin: 8px 20px 36px; aspect-ratio: 16 / 10; }
`;

const DEFAULT_ITEMS = [
  { title: "Composable building blocks", description: "Assemble flexible experiences from modular pieces, custom workflows and connected services.", meta: "Platform · 2026", linkLabel: "Explore", href: "#", background: "#E6DED2", visualLabel: "Interface preview" },
  { title: "Connected infrastructure", description: "Link products, data and actions to any front-end stack with a clean, dependable foundation.", meta: "Foundation · 2026", linkLabel: "View details", href: "#", background: "#DCEEDC", visualLabel: "System dashboard" },
  { title: "Configurable automation", description: "Wire internal systems and outside services together through event-driven, adaptable logic.", meta: "Automation · 2026", linkLabel: "Learn more", href: "#", background: "#E3DDF1", visualLabel: "Workflow editor" },
];

import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
import { useSectionRuntime, isCompactBreakpoint } from "section-runtime";

// Layered Project Showcase — heading + CTAs over a deck of website-mockup cards
// stacked on top of each other; the front card cycles with a zoom/restack on
// click or via the up/down controls. Interactive (click-driven), themeable,
// placeholder mockups + original copy.
// content: title, subtitle, primaryButtonLabel, primaryButtonHref,
//          secondaryButtonLabel, secondaryButtonHref,
//          items[] { title (project name), href, text, image }.
export default function Section({ content = {}, theme = {} }) {
  // Deliberately a DARK showcase (white website mockups pop on dark). The brand
  // accent still themes the primary button + glow.
  const t = {
    bg: "#0e0f13",
    text: "#f5f6f8",
    muted: "rgba(245,246,248,0.66)",
    surface: "#ffffff",
    border: "rgba(255,255,255,0.16)",
    btnBg: theme.buttonBgColor || theme.accentColor || "#2563eb",
    btnText: theme.buttonTextColor || "#ffffff",
    accent: theme.accentColor || theme.primaryColor || "#2563eb",
    radius: theme.radius || "14px",
    heading: theme.headingFont || "Inter, system-ui, sans-serif",
    body: theme.bodyFont || "Inter, system-ui, sans-serif",
  };
  const { width, breakpoint } = useSectionRuntime();
  const w = width || 1200;
  const mobile = isCompactBreakpoint(breakpoint);
  const reduce = useReducedMotion();

  const items = Array.isArray(content.items) && content.items.length ? content.items : DEFAULTS;
  const n = items.length;
  const [active, setActive] = useState(0);
  const go = (dir) => setActive((a) => (a + dir + n) % n);

  const padX = mobile ? 20 : breakpoint === "tablet" ? 32 : 56;
  const cardW = Math.min(w - padX * 2, mobile ? 640 : 980);
  const cardH = Math.round(cardW * (mobile ? 0.66 : 0.6));
  const stackTop = mobile ? 34 : 46; // peek height per card behind

  return (
    <section style={{ background: t.bg, color: t.text, fontFamily: t.body, padding: `${mobile ? 56 : 88}px 0 ${mobile ? 48 : 64}px`, overflow: "hidden", position: "relative" }}>
      <div style={{ position: "absolute", inset: 0, background: `radial-gradient(60% 40% at 50% 0%, ${hexA(t.accent, 0.16)}, transparent 70%)`, pointerEvents: "none" }} aria-hidden="true" />

      {/* Header */}
      <div style={{ position: "relative", maxWidth: 900, margin: "0 auto", padding: `0 ${padX}px`, textAlign: "center" }}>
        {content.eyebrow ? <p style={{ margin: "0 0 14px", textTransform: "uppercase", letterSpacing: "0.16em", fontSize: 12, fontWeight: 700, color: t.muted }}>{content.eyebrow}</p> : null}
        <h2 style={{ margin: 0, color: t.text, fontFamily: t.heading, fontWeight: 700, letterSpacing: "-0.03em", lineHeight: 1.05, fontSize: mobile ? 34 : breakpoint === "tablet" ? 48 : 62 }}>{content.title || "Make your website your competitive edge"}</h2>
        {content.subtitle ? <p style={{ margin: `${mobile ? 16 : 22}px auto 0`, maxWidth: 620, fontSize: mobile ? 16 : 19, lineHeight: 1.55, color: t.muted }}>{content.subtitle}</p> : null}
        <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center", gap: 12, marginTop: mobile ? 26 : 34 }}>
          <a href={content.primaryButtonHref || "#"} style={{ background: t.btnBg, color: t.btnText, padding: "15px 28px", borderRadius: 10, fontSize: 15.5, fontWeight: 600, textDecoration: "none" }}>{content.primaryButtonLabel || "Get started — it's free"}</a>
          {content.secondaryButtonLabel ? <a href={content.secondaryButtonHref || "#"} style={{ background: "rgba(255,255,255,0.08)", color: t.text, padding: "15px 28px", borderRadius: 10, fontSize: 15.5, fontWeight: 600, textDecoration: "none", border: `1px solid ${t.border}` }}>{content.secondaryButtonLabel}</a> : null}
        </div>
      </div>

      {/* Card deck */}
      <div style={{ position: "relative", width: cardW, maxWidth: "100%", margin: `${mobile ? 40 : 56}px auto 0`, height: cardH + stackTop * Math.min(n - 1, 3) }}>
        {items.map((item, i) => {
          const rel = (i - active + n) % n;
          const shown = rel <= 3;
          const isFront = rel === 0;
          return (
            <motion.button
              type="button"
              key={i}
              onClick={() => (isFront ? go(1) : setActive(i))}
              aria-label={isFront ? "Next project" : `Show ${item.title || "project"}`}
              initial={false}
              animate={{
                y: reduce ? 0 : -rel * stackTop,
                scale: reduce ? 1 : 1 - rel * (mobile ? 0.05 : 0.045),
                opacity: shown ? (isFront ? 1 : 0.55 - rel * 0.08) : 0,
                filter: isFront ? "brightness(1)" : "brightness(0.82)",
              }}
              transition={reduce ? { duration: 0 } : { duration: 0.95, ease: [0.33, 1, 0.68, 1] }}
              style={{
                position: "absolute", left: "50%", bottom: 0, width: cardW, marginLeft: -cardW / 2, height: cardH,
                padding: 0, border: "none", background: "transparent", cursor: "pointer",
                zIndex: n - rel, pointerEvents: shown ? "auto" : "none", transformOrigin: "bottom center",
              }}
            >
              <div style={{ width: "100%", height: "100%", borderRadius: t.radius, overflow: "hidden", background: t.surface, boxShadow: "0 30px 70px -24px rgba(0,0,0,0.6)", border: "1px solid rgba(0,0,0,0.06)", display: "flex", flexDirection: "column", textAlign: "left" }}>
                <div style={{ flex: "0 0 auto", height: mobile ? 34 : 42, display: "flex", alignItems: "center", gap: 7, padding: "0 16px", background: "#f2f2f4", borderBottom: "1px solid rgba(0,0,0,0.06)" }}>
                  <span style={{ height: 10, width: 10, borderRadius: 999, background: "#ff5f57" }} />
                  <span style={{ height: 10, width: 10, borderRadius: 999, background: "#febc2e" }} />
                  <span style={{ height: 10, width: 10, borderRadius: 999, background: "#28c840" }} />
                  <span style={{ marginLeft: 12, height: mobile ? 16 : 20, flex: 1, maxWidth: 320, borderRadius: 999, background: "#ffffff", border: "1px solid rgba(0,0,0,0.08)" }} />
                </div>
                <div style={{ position: "relative", flex: 1, minHeight: 0 }}>
                  {item.image
                    ? <img src={item.image} alt={item.title || ""} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                    : <div style={{ position: "absolute", inset: 0, display: "grid", placeItems: "center", color: "#9aa1ac", background: `linear-gradient(135deg, ${hexA(item.tint || t.accent, 0.14)}, #f6f7f9 60%)` }}>
                        <div style={{ textAlign: "center" }}>
                          <svg width="46" height="46" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.3" style={{ margin: "0 auto" }}><rect x="3" y="3" width="18" height="18" rx="2" /><circle cx="8.5" cy="8.5" r="1.5" /><path d="m21 15-5-5L5 21" /></svg>
                          <p style={{ margin: "12px 0 0", fontSize: 13, fontWeight: 600, color: "#5b6270" }}>{item.title || "Website preview"}</p>
                        </div>
                      </div>}
                </div>
              </div>
            </motion.button>
          );
        })}
      </div>

      {/* Caption + controls */}
      <div style={{ position: "relative", maxWidth: cardW, margin: "22px auto 0", padding: `0 ${mobile ? padX : 4}px`, display: "flex", alignItems: "flex-end", justifyContent: "space-between", gap: 16 }}>
        <div style={{ minWidth: 0 }}>
          <p style={{ margin: 0, color: t.text, fontSize: 15, fontWeight: 600 }}>{items[active].title || "Project"}</p>
          <a href={items[active].href || "#"} style={{ display: "inline-flex", alignItems: "center", gap: 6, marginTop: 6, fontSize: 14, color: t.muted, textDecoration: "underline", textUnderlineOffset: 3 }}>
            {items[active].linkLabel || "View website"}
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d="M7 17 17 7M8 7h9v9" /></svg>
          </a>
        </div>
        <div style={{ display: "flex", gap: 12, flex: "0 0 auto" }}>
          {[["up", -1], ["down", 1]].map(([dir, d]) => (
            <button key={dir} type="button" aria-label={dir === "up" ? "Previous" : "Next"} onClick={() => go(d)}
              style={{ height: 52, width: 52, borderRadius: 999, border: `1px solid ${t.border}`, background: "rgba(255,255,255,0.06)", color: t.text, cursor: "pointer", display: "grid", placeItems: "center" }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d={dir === "up" ? "M12 19V5M6 11l6-6 6 6" : "M12 5v14M6 13l6 6 6-6"} /></svg>
            </button>
          ))}
        </div>
      </div>
    </section>
  );
}

function hexA(c, a) {
  if (typeof c !== "string" || c[0] !== "#") return c;
  const h = c.slice(1);
  const f = h.length === 3 ? h.split("").map((x) => x + x).join("") : h;
  const r = parseInt(f.slice(0, 2), 16), g = parseInt(f.slice(2, 4), 16), b = parseInt(f.slice(4, 6), 16);
  return `rgba(${r},${g},${b},${a})`;
}

const DEFAULTS = [
  { title: "Northwind Studio", linkLabel: "View website", href: "#", tint: "#2563eb" },
  { title: "Fieldnote", linkLabel: "View website", href: "#", tint: "#16a34a" },
  { title: "Halcyon Labs", linkLabel: "View website", href: "#", tint: "#db2777" },
  { title: "Skylark Commerce", linkLabel: "View website", href: "#", tint: "#f59e0b" },
];
